const PEOPLE_TOOLS = [
  { tool: 'addAdminBeneficiary', purpose: 'This action is used by an admin to add a beneficiary to an enrollment.\ndependencyTools: getEnrollments' },
  { tool: 'addAdminEnrollment', purpose: 'This action is used by an admin to enroll a user in a benefit plan.\ndependencyTools: getBenefitPlans' },
  { tool: 'addAndTagUserKra', purpose: 'Creates a new KRA and tags it to a specific employee in one step. Requires kra_name (mandatory, max 500 chars). Optional: description (max 5000 chars), weightage (float), include_in_library (true/false to also add to org KRA library). The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'addClient', purpose: 'This action is to create a client. clientName is name of client, currency is currency of client, billingMethod is either hourly job rate or hourly user rate or hourly user rate - jobs or hourly user rate - projects' },
  { tool: 'addDependent', purpose: 'This action is used to add a new dependent for benefits.' },
  { tool: 'addEnrollment', purpose: 'This action is used to enroll an employee in a benefit plan. Requires plan ID (from getEligiblePlans), coverage option, and dependent details if applicable. Verify eligible plans before enrolling.\ndependencyTools: getEligiblePlans' },
  { tool: 'addFeedback', purpose: 'This action is used to add feedback for a given employee. It requires the employee\'s erecno and the feedback details, whether the given feedback is anonymous or not(if anonymous true or false boolean value) and fetch feedback type from `getFeedbackCategories` and map the typeName recieved from the request and send the mapped typeId while sending the request\ndependencyTools: getFeedbackCategories' },
  { tool: 'addJobSchedule', purpose: 'This action adds a job schedule for a job for a user on a specific date. date is the scheduled date, default current date in yyyy-MM-dd format. fromtime is the job start time and totime is the job end time. jobId is the id of the job to schedule, fetched from getJobs tool by job name; if multiple jobs match, prompt user to choose. isPublish is true to publish, false to save as draft. assignedTo is the employee for whom the schedule is added. isRepeat specifies if the schedule repeats. If isRepeat is true: repeatUntil (mandatory) is the end date for repetition, repeatType (mandatory) is daily, weekly, or monthly, repeatInterval (mandatory) is the interval between repetitions, values 1 to 12.\ndependencyTools: getJobs' },
  { tool: 'addLeaveType', purpose: 'Adds a new leave type in Zoho People. INVOCATION STEPS: 1. Gather all mandatory fields. 2. Show a confirmation table. 3. Invoke only after explicit user approval. MANDATORY FIELDS in \'leaveType\': name (String), code (3-letter unique code, e.g., CAS), type (PAID/UNPAID), unit (DAY/HOUR), validityFrom (date string), applicable (JSONObject with keys: Departments, Designations, Locations, Roles, Users, Genders, MaritalStatus; each has mode (1=applicable, 0=exception) and list (JSONArray of ID strings; [\'-1\'] for all); Genders list uses text like \'Male\',\'Female\'). Example for all employees: {\'Departments\':{\'mode\':1,\'list\':[\'-1\']},\'Designations\':{\'mode\':1,\'list\':[\'-1\']},\'Locations\':{\'mode\':1,\'list\':[\'-1\']},\'Roles\':{\'mode\':1,\'list\':[\'-1\']},\'Users\':{\'mode\':1,\'list\':[\'-1\']},\'Genders\':{\'mode\':1,\'list\':[\'-1\']},\'MaritalStatus\':{\'mode\':1,\'list\':[\'-1\']}}. OPTIONAL: validityTo, description, effectiveAfterUnit, effectiveAfterPeriod (0-12), creditCount, creditFrequency, resetFrequency, carryForward, encashment, exceedBalance (mode: YEAREND/NOLIMIT/LOP), weekendAsLeave, holidayAsLeave, allowFullDay, allowHalfDay, allowHour, pastBooking, futureBooking, minLeave, maxLeave, fileUpload.' },
  { tool: 'addnewhelpdeskticket', purpose: 'This action is used to create an HR help desk ticket. First extract the subject, description, category, and sub-category from the user\'s request. Use listAllCategory to resolve categoryId and subCategoryId. Infer the priority from the tone and urgency of the user\'s request: 10=Low (minor/non-urgent), 11=Medium (default when unclear), 12=High (urgent/critical). employeeId is auto-injected from the current user context. Show the extracted ticket details - subject, description, category, sub-category, and inferred priority - to the user for confirmation, and submit the request only after the user confirms.\ndependencyTools: listAllCategory' },
  { tool: 'addOnDuty', purpose: 'Submit an on-duty request for work outside office (client visits, meetings, events). Do not ask confirmation - proceed directly. Two modes based on unit param: Mode 1 (unit=0, day-based): dataObj per date has dayTaken (0=full, 1=half, 2=quarter) and session. Full day: no session. Half: session 1 or 2. Quarter: session 1-4. Default: full day. Mode 2 (unit=1, hours-based): dataObj per date has ftime/ttime in mins from midnight (09:00AM=540, 02:00PM=840). Before invoking: 1. Call getAllODTypes. One type = use it. Multiple = fuzzy-match user input; ask only if no match. 2. Pick mode: from/to times -> unit=1, else unit=0 (default full day). 3. type=\'addData\'. 4. startDate/endDate in dd-MMM-yyyy (same for single day). 5. dateFormat=\'dd-MMM-yyyy\'. 6. dataObj: keys=date strings (dd-MMM-yyyy), values=mode-specific fields. 7. Pass desc only if user explicitly provides a reason.\ndependencyTools: getAllODTypes' },
  { tool: 'addOrgCompetencies', purpose: 'Creates new competencies at the organisation level. The competencies parameter is required and must be a JSON array of competency objects following the addorg template in which name param for competency name and description param for competency description alone should be used.' },
  { tool: 'addOrgKras', purpose: 'Creates new KRAs at the organisation level. The kras parameter is required and must be a JSON array of KRA objects following the addkraorg template in which name param for kra name , description param for kra description , maximum_range param for kra weightage maximum range and minimum_range param for kra weightage minimum range alone should be used. In response show type key represents 0 as Organisation KRA , 2 as User KRA' },
  { tool: 'addOrgReviewQuestions', purpose: 'Adds new review questions to the organisation. The questions parameter is required and must be a JSON array of question objects following the addquestionorg template in which question param alone must be used ,it should be mandatory.' },
  { tool: 'addOrgSkills', purpose: 'Creates new skills at the organisation level. The skills parameter is required and must be a JSON array of skill objects following the add template in which name param for skill name and description param for skill description alone should be used.' },
  { tool: 'addProvider', purpose: 'This action is used to add a new benefit provider to the organization.' },
  { tool: 'addRecord', purpose: 'Add a record. Flow: identifyForm -> getFields -> match user input -> construct inputData using RECORD_ADD_UPDATE PromptSection. STRICT - Lookup fields: call getLookupOptions; each labelname maps to [{Value,Id}] objects; match user text against Value and send Id. NEVER send display strings for Lookup fields. Picklist/Dropdown: call getFieldOptions; match case-sensitively; if no exact match, show options and ask to choose or quick-add. Gender/BloodGroup/Country: call getFieldOptions; Options object has keys=identifiers, values=display texts; match case-sensitively; if no match, show options and ask. NEVER send a value not in the fetched options list. If Lookup Id cannot be resolved, ask user to choose from options or provide the Id. Pass final field data as inputData to complete record creation.\ndependencyTools: identifyForm, getFields, getFieldOptions, getLookupOptions' },
  { tool: 'addRegularization', purpose: 'Submit a regularization request to correct missed/incorrect attendance entries. All dates: dd-MMM-yyyy format.      Before invoking:      1. Call getAllRegReasons. If reasons exist, fuzzy-match user\'s choice to exact list entry. If empty, omit reasonanddesc from data.      2. Collect date, check-in/out times, and reason (from the valid list if applicable) from user.      3. Convert times to mins from midnight (09:00 AM=540, 06:00 PM=1080).      4. Set type=\'addData\'.      5. startDate and endDate in dd-MMM-yyyy (same for single day).      6. dateFormat=\'dd-MMM-yyyy\'.      7. regFromTime/regToTime = check-in/out in mins.      8. attendDate = date being regularized (dd-MMM-yyyy).      9. data = JSON keyed by date (dd-MMM-yyyy). Each entry: {ftime, ttime, fromDate, toDate, reasonanddesc:{reason:"..."}}. Omit reasonanddesc if reasons not enforced.      10. IMPORTANT: URL-encode the data parameter value before passing.\ndependencyTools: getAllRegReasons' },
  { tool: 'addShiftChangeRequest', purpose: 'Create/submit a shift change request. Do not ask for confirmation; proceed directly with available information. Before invoking: 1. erecno: Employee(s) whose shift changes. Supports multiple comma-separated erecnos in one call. Do NOT call separately per user when shift and dates are identical. 2. Fetch applicable shifts via getApplicableShiftsForUser. Use the single shift if only one exists. Fuzzy-match user\'s named shift; if no match, ask user to select. 3. shiftid: ID of target shift from getApplicableShiftsForUser. 4. fdate (start) and tdate (end) in dd-MMM-yyyy. For single-day change, both are the same. 5. dateFormat: \'dd-MMM-yyyy\'. 6. desc: Pass only if user explicitly provides a reason. Do not infer or auto-generate. 7. Always pass update=\'true\' and updateAttEntries=\'true\'.\ndependencyTools: getApplicableShiftsForUser' },
  { tool: 'addTimelog', purpose: 'This action is to add timelog or log time for a user, it is a mandatory field always fetch it from the current user\'s erecno and pass it as an argument in all cases or the mentioned user\'s erecno, jobName is a job that time is logged, user is the Employee for whom time logs is added default is current user, workDate is the date to log time (derive from today\'s date from system instruction\'s DATE section and convert to yyyy-MM-dd format), hours is duration for the timelog, fromTime is start and endTime is end of time log, billingStatus is either billable or non-billable default value is billable and is mandatory field, dateFormat is the format of workDate that is used. jobId is id of job and will be given priority to this in place of jobName if both are available\ndependencyTools: getJobs' },
  { tool: 'addUserBeneficiary', purpose: 'This action is used to add a beneficiary to a user\'s enrollment.' },
  { tool: 'addWindowEnrollment', purpose: 'This action is used to enroll a user in a list of plans from an enrollment window.\ndependencyTools: getUserEnrollmentWindowPlans' },
  { tool: 'allCaseslist', purpose: 'get all HR cases listing for the user if the index is not mentioned always send index=0' },
  { tool: 'applyLeave', purpose: 'Applies for leave on behalf of the user. Before invoking: 1. Call fetchLeaveBasicInfo to get the formlinkname. 2. Use formlinkname to call getFields and identify mandatory fields. 3. Call getLeaveBalance to retrieve applicable leave types and balances. 4. Show only leave type names to the user as a selectable list; map the selected name to its leaveTypeId internally. 5. Resolve the correct erecno from context - use current user\'s erecno if no name is mentioned; if a person (e.g., \'Ramesh\') is mentioned, resolve their erecno from employee context. Never take erecno from user input. 6. Build inputData using field label names as keys. Mandatory fields: Employee ID (resolved erecno - NEVER from user input), Leave Type (resolved leaveTypeId - NEVER from user input), From, To, Reason. 7. Format inputData as a string and pass it. Skip re-invoking dependent tools if formlinkname and balance data are already available.\ndependencyTools: fetchLeaveBasicInfo, getFields, getLeaveBalance' },
  { tool: 'applyPermission', purpose: 'Submit a permission request for non-worked time within the org\'s maximum allowed duration. Do not ask confirmation; proceed directly. Before invoking: 1. Call getApplicablePermForUser to get permission types. One type = use directly. Multiple = fuzzy-match user\'s request against type names (typos, partial matches, synonyms); use matched type or ask user to select if no match found. Do NOT default to first type. 2. Use date, from-time, and to-time from user\'s request. 3. Convert times to mins from midnight (e.g., 02:00 PM=840, 03:00 PM=900, 11:30 AM=690). 4. Construct input JSON with all values as strings: erecno, date (dd-MMM-yyyy), permissionId, fromTime, toTime, and reason (if provided).\ndependencyTools: getApplicablePermForUser' },
  { tool: 'approvalReject', purpose: 'This action is used to approve or reject a record.pkid is a UUID number that is used to identify the approval,     status is regex used to approve or reject an request,remarks are the comments that are given by the user while approving/rejecting.\ndependencyTools: getApprovals' },
  { tool: 'approveEnrollment', purpose: 'This action is used to approve a pending enrollment request.\ndependencyTools: getEnrollments' },
  { tool: 'cancelcompoff', purpose: 'The tool is used to cancel an existing compensatory off request. It requires the recordId of the compsentory record that needs to be cancelled. Always extract the values from the users request before invoking the tool.\ndependencyTools: getCompoffRecords' },
  { tool: 'cancelLeave', purpose: 'The tool is used to cancel an existing leave request. It requires the recordId of the leave entry that needs to be cancelled and a reason for cancellation. Always extract both values from the users request before invoking the tool.\ndependencyTools: getLeaveRecords' },
  { tool: 'changeTaskOwner', purpose: 'This action changes the owner of a task. It requires the taskId and the employee record number (erecno) of the new taskowner.\ndependencyTools: getMyTasks, getEmployeeBasicDetails' },
  { tool: 'checkIn', purpose: 'This tool can be used by by self user alone. No user can use this tool on behalf of another user. This action is used to mark user\'s checkIn/punchIn/End a break.      To mark checkIn/punchIn or end a break:     It starts by retrieving the current attendance status of user using the getStatus tool, retrieve allowedToCheckIn from the response.      If it\'s true only then checkIn action can be allowed else return error  user is already in checked in state.\ndependencyTools: getStatus_or_getBreaks' },
  { tool: 'checkOut', purpose: 'This tool can be used by by self user alone. No user can use this tool on behalf of another user. This action is used to mark user\'s checkOut/punchOut/Start a break.      To mark checkOut/punchOut:     It starts by retrieving the current attendance status of user using the getStatus tool, retrieve allowedToCheckIn from the response.      If it\'s false only then checkOut action can be allowed else return error  user is already in checked out state.          To start the break:      First invoke getStatus_or_getBreaks tool and get breakId from user. Use the breakId in checkOut tool parameter to start break\ndependencyTools: getStatus_or_getBreaks' },
  { tool: 'completeEnrollmentWindow', purpose: 'This action is used to complete the enrollment requests for an enrollment window.\ndependencyTools: getEnrollmentWindows' },
  { tool: 'completeTask', purpose: 'This action changes the status of the task to \'completed\', it requires taskid.\ndependencyTools: getMyTasks' },
  { tool: 'createBenefitCategory', purpose: 'This action is used to create a new benefit category in the organization.' },
  { tool: 'createBenefitPlan', purpose: 'This action is used to create a new benefit plan in the organization.' },
  { tool: 'createDivision', purpose: 'Creates a new division in the organization structure. Requires \'name\' (mandatory, must be unique within divisions). Optional parameters: \'description\' (text description), \'zp_code\' (unique short code, max 10 characters, no angle brackets), and \'parent_division\' (ID of the parent division for creating nested divisions). Returns the newly created division\'s zoho_id on success. Error codes: 0 = duplicate name, 1 = empty name, 5 = duplicate zp_code, 6 = empty zp_code, 7 = invalid zp_code, 8 = zp_code too long.' },
  { tool: 'createEnrollmentWindow', purpose: 'This action is used to create a new enrollment window.' },
  { tool: 'createEntity', purpose: 'Creates a new legal entity in the organization structure. Requires \'name\' (mandatory, must be unique within legal entities). Optional parameters: \'description\' (text description) and \'zp_code\' (unique short code, max 10 characters, no angle brackets). Returns the newly created entity\'s zoho_id on success. Error codes: 0 = duplicate name, 1 = empty name, 5 = duplicate zp_code, 6 = empty zp_code, 7 = invalid zp_code, 8 = zp_code too long.' },
  { tool: 'createPlanYear', purpose: 'This action is used to create a new plan year.' },
  { tool: 'createUnit', purpose: 'Creates a new business unit in the organization structure. Requires \'name\' (mandatory, must be unique within business units). Optional parameters: \'description\' (text description) and \'zp_code\' (unique short code, max 10 characters, no angle brackets). Returns the newly created unit\'s zoho_id on success. Error codes: 0 = duplicate name, 1 = empty name, 5 = duplicate zp_code, 6 = empty zp_code, 7 = invalid zp_code, 8 = zp_code too long.' },
  { tool: 'deleteLeaveType', purpose: 'This tool is used to delete an existing leave type from Zoho People leave settings. Before invoking: 1. Call fetchLeaveTypes to resolve the leave type name to its leaveTypeId. 2. Confirm with the user before deleting, as this action will permanently delete the leave type and its report data cannot be recovered. This tool requires no request parameters other than the leaveTypeId in the URL path.\ndependencyTools: fetchLeaveTypes' },
  { tool: 'deleteTimelogs', purpose: 'This action is to delete timelogs, timeLogId is Mandatory field,  It starts by retrieving the time log using getTimelogs tool for a certain period and send the timelog ids as comma seperated values\ndependencyTools: getTimelogs' },
  { tool: 'denyEnrollment', purpose: 'This action is used to deny a pending enrollment request.\ndependencyTools: getEnrollments' },
  { tool: 'disableBenefitPlan', purpose: 'This action is used to disable a benefit plan.\ndependencyTools: getBenefitPlans' },
  { tool: 'disableEnrollmentWindow', purpose: 'This action is used to disable an enrollment window.\ndependencyTools: getEnrollmentWindows' },
  { tool: 'disablePlanYear', purpose: 'This action is used to disable a plan year.\ndependencyTools: getPlanYear' },
  { tool: 'downloadBenefitFile', purpose: 'This action is used to download a benefits entity file.' },
  { tool: 'editJobSchedule', purpose: 'This action is to edit a existing job schedule,jobScheduleId is id fetched from getJobSchedule tool or addJobSchedule tool, date specifies on which date its has to be changed default current date in yyyy-MM-dd format. fromtime is start of job and totime is end of the job that is scheduled, jobId is id for the job for which scheduled is added takes previous value or value from getJobs tool, isPublish is true when user want to publish the job or it will be saved as draft, assignedTo is employee for whom the job schedule is edited.     isRepeat specify if the job schedule needs to be repeated, repeatUntil is mandatory if isRepeat is true specify the date until when the job schedule needs to be repeated, repeatType is mandatory if isRepeat is true values are daily or weekly or monthly, repeatInterval specify the interval for which the job schedule needs to be repeated and is Mandatory if isRepeat is true and values are between 1 to 12\ndependencyTools: getJobSchedule, addJobSchedule, getJobs' },
  { tool: 'editLeaveType', purpose: 'Updates an existing leave type in Zoho People. Before invoking: 1. Call fetchLeaveTypes to resolve the leave type name to its leaveTypeId. 2. Confirm which fields to update. 3. Build \'leaveType\' JSON with ONLY the fields the user wants to change. Mandatory fields always required: name (String), code (3-letter String), type (PAID/UNPAID), unit (DAY/HOUR), validityFrom (date string), applicable (JSON object; keys: Departments, Designations, Locations, Roles, Users, Genders, MaritalStatus; each has mode (\'1\'=include, \'0\'=exception) and list (JSON array of ID strings; [\'-1\'] for all). Example: {\'Departments\':{\'mode\':\'1\',\'list\':[\'-1\']},\'Designations\':{\'mode\':\'1\',\'list\':[\'-1\']},\'Locations\':{\'mode\':\'1\',\'list\':[\'-1\']},\'Roles\':{\'mode\':\'1\',\'list\':[\'-1\']},\'Users\':{\'mode\':\'1\',\'list\':[\'-1\']},\'Genders\':{\'mode\':\'1\',\'list\':[\'-1\']},\'MaritalStatus\':{\'mode\':\'1\',\'list\':[\'-1\']}}). Optional: validityTo, description, effectiveAfterUnit, effectiveAfterPeriod (0-12), creditCount, creditFrequency, resetFrequency, carryForward, encashment, exceedBalance (mode: YEAREND/NOLIMIT/LOP), weekendAsLeave, holidayAsLeave, allowFullDay, allowHalfDay, allowHour, pastBooking, futureBooking, minLeave, maxLeave, fileUpload. Confirm changes before invoking.\ndependencyTools: getLeaveBalance' },
  { tool: 'editOrgCompetencies', purpose: 'Updates existing competencies at the organisation level. The competencies parameter is required and must be a JSON array of competency objects following the editorg template in which zoho_id param for competency id , name param for competency name and description param for competency description alone should be used. Dependencies: [getOrgCompetencies]\ndependencyTools: getOrgCompetencies' },
  { tool: 'editOrgKras', purpose: 'Updates existing KRAs at the organisation level. The kras parameter is required and must be a JSON array of KRA objects following the editkraorg template in which zoho_id param for kra id , name param for kra name , description param for kra description,                      maximum_range param for kra weightage maximum range and minimum_range param for kra weightage minimum range alone should be used. Dependencies: [getOrgKras]\ndependencyTools: getOrgKras' },
  { tool: 'editOrgReviewQuestions', purpose: 'Edits existing review questions in the organisation. The questions parameter is required and must be a JSON array of question objects following the editquestionorg template in which zoho_id param for question_id and question param for question. Dependencies: [getOrgReviewQuestions]\ndependencyTools: getOrgReviewQuestions' },
  { tool: 'editOrgSkills', purpose: 'Updates existing skills at the organisation level. The skills parameter is required and must be a JSON array of skill objects following the edit template in which zoho_id param for skill id, name param for skill name and description param for skill description alone should be used. Dependencies: [getOrgSkills]\ndependencyTools: getOrgSkills' },
  { tool: 'editTimelog', purpose: 'This action is to edit timelog, timeLogId is Mandatory field,  It starts by retrieving the time log using the addTimelog tool or getTimelogs tool, user it is a mandatory field always fetch it from the current user\'s erecno and pass it as an argument in all cases or the mentioned user\'s erecno,jobName is a job that time is logged, user is the Employee for whom time logs is added, workDate is the date to log time (derive from today\'s date from system instruction\'s DATE section and convert to yyyy-MM-dd format), hours is duration for the timelog, fromTime is start and endTime is end of time log, billingStatus is either billable or non-billable default value is billable\ndependencyTools: getTimelogs, addTimelog' },
  { tool: 'editUserCompetencies', purpose: 'Edits competencies tagged to a specific employee. The competencies parameter is required and must be a JSON array of competency objects following the edituser template in which zoho_id param for competency user record id , weightage param for weightage alone should be allowed.. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUserCompetencies]\ndependencyTools: getEmployeeBasicDetails, getUserCompetencies' },
  { tool: 'editUserKras', purpose: 'Edits KRAs tagged to a specific employee. The kras parameter is required and must be a JSON array of KRA objects following the edit template in which zoho_id param for kra user record id , weightage param for weightage alone should be allowed. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUserKras]\ndependencyTools: getEmployeeBasicDetails, getUserKras' },
  { tool: 'editUserSkills', purpose: 'Edits skills tagged to a specific employee. The skills parameter is required and must be a JSON array of skill objects following the edituser template in which zoho_id param for skill user record id, level param for skill level alone should be allowed. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUserSkills]\ndependencyTools: getEmployeeBasicDetails, getUserSkills' },
  { tool: 'employeeInsights', purpose: 'Fetches employee count and insights for the organization. Use repType to control the scope: \'myReports\' for the current user\'s direct reportees, \'teamReports\' for the full team under the current user, or \'adminReports\' for all employees (admin only). Returns a summary with total employee count (activeEmpCount), department-wise breakdown (deptWiseCount array with deptName and count), designation-wise breakdown (designationWiseCount array), location-wise breakdown (locationWiseCount array), and employee type breakdown (empTypeWiseCount array). Display results in a clear tabular format grouped by category. If the user asks about headcount, team size, or workforce distribution, use this tool. For attrition or turnover analysis, use getAttritionReport instead.' },
  { tool: 'enableBenefitPlan', purpose: 'This action is used to enable a benefit plan.\ndependencyTools: getBenefitPlans' },
  { tool: 'enableEnrollmentWindow', purpose: 'This action is used to enable an enrollment window.\ndependencyTools: getEnrollmentWindows' },
  { tool: 'enablePlanYear', purpose: 'This action is used to enable a plan year.\ndependencyTools: getPlanYear' },
  { tool: 'fetchallgroups', purpose: 'This action retrieves all the groups ' },
  { tool: 'fetchEmployeeRecordById', purpose: 'Retrieve the employee record for the given record ID.' },
  { tool: 'fetchEmployeeSalaries', purpose: 'This action is used to list of employee\'s compensation details which includes salary, package details, effective from, currencies.Parse zpu[erecno:{id}]zpu associated with this request as erecno and pass it request url.\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'fetchForms', purpose: 'Retrieve the list of forms and their details from Zoho People.' },
  { tool: 'fetchgroupmembers', purpose: 'Retrieve all the group members from the group' },
  { tool: 'fetchLeaveBasicInfo', purpose: 'For any leave related query. This tool is for internal use only and should not be exposed to the user.And use this response as formlinkname for `applyLeave` tool' },
  { tool: 'fetchLeaveTypeDetails', purpose: 'Fetches the full configuration details of a specific leave type by its ID. Returns complete leave type settings including: name, code, type (PAID/UNPAID), unit (DAY/HOUR), validityFrom, validityTo, description, creditCount, creditFrequency, resetFrequency, applicability criteria (Departments, Genders, Designations, Locations, Roles, MaritalStatus, Users), weekendAsLeave, holidayAsLeave, allowFullDay, allowHalfDay, allowQuarterDay, allowHour, minLeave, maxLeave, fileUpload, exceedBalance, carryForward, encashment, pastBooking, futureBooking, and effectiveAfter settings. Use fetchLeaveTypes to obtain the leaveTypeId before calling this tool. Admin-only access.\ndependencyTools: fetchLeaveTypes' },
  { tool: 'fetchLeaveTypes', purpose: 'Fetches the summary list of all configured leave types in Zoho People leave settings. Use this when the user wants to list, view, browse, or check all available leave types, leave policies, or leave categories. Returns each leave type\'s id, name, color, unit (DAY/HOUR), and type (PAID/UNPAID). This returns summary data only - for the full configuration of a specific leave type, use fetchLeaveTypeDetails after this tool. This tool is also the prerequisite for fetchLeaveTypeDetails, editLeaveType, and deleteLeaveType to resolve a leave type name to its leaveTypeId. Supports pagination via startIndex (default: 1) and limit (default: 30).' },
  { tool: 'fetchmygroups', purpose: 'This action retrieves the groups associated with the current user' },
  { tool: 'fetchRevisions', purpose: 'This action is used to get employees salary revision details which includes Revised Salary, Revised Amount, Revised Percentage, Reason for Revisions, Salary packages' },
  { tool: 'fetchSalaryComponents', purpose: 'This action is used to get configured salary or benefit components list eg, basic pay , HRA, bonus etc. which includes components code, component name, payment frequencies, earning or deduction, calculation type, calculation value.' },
  { tool: 'fetchSalaryPackageComponents', purpose: 'This action is used to find the packageId from the `fetchSalaryPackages` response and get the salary components details configured with it\ndependencyTools: fetchSalaryPackages' },
  { tool: 'fetchSalaryPackages', purpose: 'This action is used to get configured salary package details , which includes package name, package applicablities' },
  { tool: 'fetchSingleEmployeeBreakupDetails', purpose: 'This action is used to get specific employee\'s compensation breakup details which includes ctcComponent i.e part of user salary and benefits which is given as additional perk to user eg. bonus, gift card etc.Parse zpu[erecno:{id}]zpu associated with this request as erecno and pass it request url.\ndependencyTools: getEmployeeBasicDetails, getRecords' },
  { tool: 'fetchSingleEmployeeRevisions', purpose: 'This action is used to get specific employee salary revision details which includes Revised Salary, Revised Amount, Revised Percentage, Reason for Revisions, Salary packages.Parse zpu[erecno:{id}]zpu associated with this request as erecno and pass it request url.\ndependencyTools: getEmployeeBasicDetails, getRecords' },
  { tool: 'fetchSingleEmployeeSalary', purpose: 'This action is used to get specific employee\'s compensation details which includes salary, package details, effective from, currencies.\ndependencyTools: getEmployeeBasicDetails, getRecords' },
  { tool: 'fetchTaskComments', purpose: 'This action retrieves the comments for a specific task, along with details of the employees who commented. It requires a taskid.\ndependencyTools: getMyTasks' },
  { tool: 'fileModulePermInitialData', purpose: 'For any files related operations. This tool is for internal use only and should not be exposed to the user.And use this response for checking the user permission for `getAllFiles` tool' },
  { tool: 'getAdminEnrollmentBeneficiaries', purpose: 'This action is used to fetch the list of all beneficiaries for an enrollment (admin view).\ndependencyTools: getEnrollments' },
  { tool: 'getAllFiles', purpose: 'Retrieves organisation files. Defaults: fileType=1, start=0, limit=100, fileSortByType=3, isFileSortDesc=true. Filters: roleId, catId, locationId (comma-separated), employeeId, entityId, unitId, divisionId, deptId. filterView controls scope (location|entity|unit|division|department, default location); when query mentions \'company\', use entity filter. searchFileName (no special chars, max 250) and searchFileExtn filter by name/extension. fromDate/toDate set date range. fileSortByType (1=name, 2=created, 3=modified), isFileSortDesc (true=desc). Before invoking: 1) Call fileModulePermInitialData. 2) Read loginUserRoleCheck: if -1, pass isFromModule=true; if 0/1/2, pass filterView (default Location). File Download: if query contains \'download\': check allowDownload=true, extract fileName/fileID/filePath, output {"file_tool_response":{"_for_pfile":"true","_file_download_card":"true","file_name":"...","file_id":"...","file_path":"...","response_message":"..."}}. Non-downloadable: {"file_tool_response":{"_for_pfile":"true","response_message":"..."}}. Do not generate download links directly. One file at a time only. Output must be valid JSON.\ndependencyTools: fileModulePermInitialData' },
  { tool: 'getAllODTypes', purpose: 'This tool fetches all available on-duty types configured in the organization. The response contains the list of on-duty types with their IDs and names. Use this tool before creating an on-duty request to get the applicable on-duty type ID.' },
  { tool: 'getAllRegReasons', purpose: 'This tool fetches all configured regularization reason types for the organization. The response contains a JSON array of valid reason strings. Use this tool before creating a regularization request to get the list of allowed reasons. If the response returns an empty array or no reasons, it means regularization reasons are not enforced. If reasons are returned, the user MUST use one of them. When the user provides a reason, match it to the closest reason from the returned list (handle spelling mistakes, partial matches, synonyms, or paraphrasing) and use the exact string from the list in the API call. Only ask the user to clarify if no reasonable match can be found. Present the available reasons to the user and let them choose.' },
  { tool: 'getApplicablePermForUser', purpose: 'This tool fetches the applicable permission types for a specific user. The response contains the list of permission types with their IDs, names, and allowed duration. Use this tool before creating a permission request to get the applicable permission type ID and allowed limits.      Pass the erecno of the user for whom applicable permissions need to be fetched.' },
  { tool: 'getApplicableShiftsForUser', purpose: 'This tool fetches the applicable shifts for a specific user that they can request to change to. The response contains the list of shifts with their IDs and names. Use this tool before creating a shift change request to get the available shift options.      Pass the erecno of the user as a JSONArray. Use current user\'s erecno if no other user is mentioned.' },
  { tool: 'getAppraisalCycles', purpose: 'Fetches the list of appraisal cycles configured in the organisation. The response includes cycle name, cycle ID (used as cycleId in other tools), cycle status, configured review types (self, multirater, appraiser), start and end dates, and applicable employee groups. Supports pagination via the following parameters: offset (int, must be greater than 0) sets the starting index of results; limit (int, range 1-200) controls the maximum number of cycles returned per request. If neither is specified, all cycles are returned. Use this tool whenever you need to identify a specific cycle before calling getReviewStatus or any cycle-dependent action.' },
  { tool: 'getAppraisalFinalRatingsofUser', purpose: 'Fetches the final appraisal ratings of a specific employee across their last N completed appraisal cycles. The employee_erecno in the URL identifies the target employee. For the current user, use the logged-in user\'s own erecno. For any other employee, first resolve their name or employee ID to an erecno using the getEmployeeBasicDetails tool. Supports pagination via the following parameters: offset (int, must be greater than 0) sets the starting index of results; limit (int, range 1-200) controls the maximum number of cycle ratings returned. The response includes cycle name, final rating score, rating label, and review completion details for each cycle. By default set limit as 5.\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getApprovals', purpose: 'Retrieve approval listings and requests based on filters. Use action=\'myApprovals\' to get items pending your approval (approve/reject), or action=\'myRequests\' to get requests you have submitted. Filter approvalStatus by: pending | approved | rejected | approvedorrejected | cancelled | all. Note: \'cancelled\' applies only to action=\'myRequests\' and is not applicable to \'myApprovals\'. Optional filters include: erceno (ERECNO of the approver); servicename to restrict by module (Performance | Leavetracker | Attendance | Timetracker, etc.); and recordOwner (ERECNO of the record owner, for action=\'myApprovals\'). If servicename=\'LEAVE\', set getBasicDetails=true.' },
  { tool: 'getAttendanceDetailedReport', purpose: 'Fetch per-date attendance details for one or more users. Omit erecno for all users; pass erecno for specific users. All-users response: result[i].employeeDetails has mailId, erecno, lastName, firstName, id. result[i].attendanceDetails[date] has: ShiftStartTime, ShiftEndTime, ShiftName, Status, FirstIn, FirstIn_Location, LastOut, LastOut_Location, TotalHours, WorkingHours, DeviationTime, paidBreakHours, unPaidBreakHours (all strings). Single-user response (erecno passed): path is [date] and also includes OverTime. All time values are strings (hh:mm or hh:mm AM/PM). FirstIn/LastOut may be \'-\' if absent.' },
  { tool: 'getAttendanceSummary', purpose: 'Fetch attendance summary per user: payable days, worked hours, overtime, leave, weekend, holiday counts. Pass erecno as comma-separated string for specific users; omit for all (200 per batch, use sIndex for pagination). Navigate to summaryReport[i] per user. Key fields: deptName, emailId, name, employeeId; totalDays, expectedWorkingDays, totalWorkedDays, absentDays, weekendDays, holidayDays, paidLeaveDays, LOPDays, onDutyDays, totalPaidOffDays, totalPayableDays (numbers); expectedWorkingHours, totalWorkedHours, weekendHours, holidayHours, totalPaidOffHours, totalPayableHours, overTime, deviationTime, netOvertime (secs, convert to hh:mm); paidLeaveHours, LOPHours, onDutyHours (string hh:mm); totalPaidBreakHours (string hh:mm); nonStatWeekend_ot, zp_HolidaySecs, holiday_ot, lateNightWorkingHours, totalUnPaidBreakInSecs (secs). Ignore all other fields.' },
  { tool: 'getAttritionReport', purpose: 'Fetches employee attrition/turnover reports. repType: \'myReports\'/\'teamReports\'/\'adminReports\' controls scope. periodCategory: \'monthly\' (default, 12 months), \'quarterly\' (4 quarters), \'half-yearly\', \'yearly\'. For monthly, pass specificCategStMon/specificCategEnMon (1-12). For yearly, pass specificCategVal as year. intervalType: \'specific\' for custom range, \'generic\' for standard. groupByField: group by \'Department\', \'Designation\', \'Location\', \'Gender\', \'EmployeeType\'. areHderDtlsNeeded/areFilterDtlsNeeded: \'true\' to include metadata. horizIndex: pagination for horizontal data. stIndex: start index for drill-down. Response has attritionData array with period labels and counts. Display as table. For drill-down, recall with matching params. exportType=\'csv\' for export. For workforce size use employeeInsights instead.\ndependencyTools: getDepartmentDetails, getLocationDetails' },
  { tool: 'getBenefitCategories', purpose: 'This action is used to get the list of benefit categories configured in the organization such as Health, Dental, Vision, Life Insurance, Retirement etc.' },
  { tool: 'getBenefitCategoryDetail', purpose: 'This action is used to get detailed information of a specific benefit category.\ndependencyTools: getBenefitCategories' },
  { tool: 'getBenefitPlanDetail', purpose: 'This action is used to get detailed information of a specific benefit plan including coverage options, contribution details, eligibility rules, and plan documents.\ndependencyTools: getBenefitPlans' },
  { tool: 'getBenefitPlans', purpose: 'This action is used to get the list of benefit plans configured in the organization including plan name, plan type, category, provider, and status.' },
  { tool: 'getClientDetails', purpose: 'Retrieve the details of a specific client using the clientId.' },
  { tool: 'getClients', purpose: 'This action is to get clients. assignedTo is user by default current user or set of user for whom clients need to be fetched given as comma seperated erecno. isFromFilter and includeDeptClients are always sent as true to fetch clients assigned to user. searchKey is used to search for specific clients.' },
  { tool: 'getCompletedTasks', purpose: 'This action retrieves tasks marked as \'Completed\' from the user\'s task list.' },
  { tool: 'getCompoffRecords', purpose: 'The tool is used to fetch the list of compensatory off records. Date params must be provided in the format dd-MMM-yyyy (e.g., 18-Aug-2025).' },
  { tool: 'getCurrentlyRunningTimer', purpose: 'This API retrieves the currently running timer information.' },
  { tool: 'getDepartmentDetails', purpose: 'This action is used to fetch department basic details such as lead/head,parent department of a department,count of members in a department.Get department name as input and pass it value to searchText param.Make sure the department name is correct from the department list given in the prompt.Strictly use this tool when basic details are needed and data is fetched based on department name.' },
  { tool: 'getDepartmentShiftGrouping', purpose: 'Fetch shift-wise grouped employees for a department or reportees on a single date. Key Features: - Shift employee count = size of that shift\'s employee array. - Report count available when filterMode=members. - Total grouped employee count in employeeCount. - Supports single date only (defaults to current date). Parameters: - filterMode (mandatory): \'members\' = Department members; \'reportees\' = Current user\'s reportees. - dataSelect (optional, only if filterMode=reportees): 1 = Direct reportees (default), 2 = All reportees. - customDate (optional): dd-MMM-yyyy (defaults to current date). - departmentId (optional): Only if filterMode=members (defaults to current user\'s department). Resolve via getDepartmentDetails if not provided. Response (result.data): - shiftInfo -> Shift metadata (shiftName, fTime, tTime, colorCode). - shiftWiseEmployeesList -> Employees grouped by shiftId. - employeeCount -> Total grouped employees. - all / direct -> Reportee count details.' },
  { tool: 'getDependentDetail', purpose: 'This action is used to get detailed information of a specific dependent.\ndependencyTools: getDependents' },
  { tool: 'getDependents', purpose: 'This action is used to get the list of dependents configured for benefits.' },
  { tool: 'getDivisions', purpose: 'Retrieves a list of all divisions in the organization structure. Supports pagination via \'offset\' (1-based page number, default 1) and \'limit\' (records per page, 1-200, default 200). Use the \'is_tagged\' parameter to filter: 1 = divisions tagged in the hierarchy tree (have entries in OrgStructureMapping), 0 = divisions not tagged. Only active, non-dummy records are returned. Divisions support nesting - a division can be a child of another division. IMPORTANT: If the user refers to Divisions using a custom display name (as specified in the system prompt), use this tool - do NOT use any other tool such as getAllFiles or getRecords.' },
  { tool: 'getEarlyLateCheckInData', purpose: 'Fetch early/late check-in and check-out details for employees. Pass erecno as comma-separated string for specific users; omit for all (up to 200 per batch). From JSON, navigate to report.empDetails (nested array). For each object: dateStr=Date; shiftId=match with report.shiftDetails to get shiftName; firstIn=First Check-In; lastOut=Last Check-Out (blank if missing); earlyLateComeTime=convert secs to hh:mm (negative=\'Late by hh:mm\', positive=\'Early by hh:mm\'); earlyLateLeaveTime=convert secs to hh:mm (negative=\'Left Early by hh:mm\', positive=\'Worked Extra by hh:mm\'). Output: Date: dateStr | Shift: shiftName | First In: firstIn | Last Out: lastOut | Check In Status | Check Out Status.' },
  { tool: 'getEligiblePlans', purpose: 'This action is used to get the list of benefit plans that the current user or a specific employee is eligible to enroll in.' },
  { tool: 'getEligibleUsersForPlan', purpose: 'This action is used to fetch the list of all eligible users for a specific benefit plan and plan year.\ndependencyTools: getBenefitPlans, getPlanYear' },
  { tool: 'getEmployeeBasicDetails', purpose: 'FIRST-CHOICE tool for employee lookup by name, employeeId/erecno, department, or designation. Paginate with sIndex/limit for bulk listings. Returns basic fields only: name, email, erecNo, employeeId, dept, designation, contact, manager. Clarify if input matches both dept and designation. Name ambiguity: auto-select by priority - 1)Reportees/Manager 2)Dept 3)Designation 4)Location 5)Role; first on tie; inform user of other matches. Prefer erecno/employeeId/zpu token over name. Falls back to getRecords(employee form) on failure. FALLBACK (STRICT): on error/missing fields/no record - suggest only employee form getRecords; use employeeType=inactive for ex-employees; never suggest unrelated tools. ZERO-RESULTS + EXIT INTENT: if totalRecords=0 with exit keywords (exit, resigned, terminated, offboarded) ask user before searching inactive via getRecords(employeeType=inactive). EXIT/OFFBOARDED: skip this tool for explicit exit/offboarded queries; use getRecords(employeeType=inactive) directly.' },
  { tool: 'getEmployeeBenefitSummary', purpose: 'This action is used to get a comprehensive summary of an employee\'s benefits including all active enrollments, total contributions, coverage details, and benefit status.' },
  { tool: 'getEmployeeShiftDetails', purpose: 'Fetch employee shift details for a given date range using employee, department, or location filters. Parameters: - erecno (optional): Comma-separated Erecno(s). - departmentId (optional): Department ID (resolve via getDepartmentDetails). - locationId (optional): Location ID (resolve via getLocationDetails). - sDate, eDate (optional): dd-MMM-yyyy (default: today). If no filter provided, fetches all employees. Response: result.data (Array). Fields: empId, empname (sanitize), emailId, deptId, locId, date-wise shiftList. Each shift: shiftName, ftime, ttime (convert to HH:mm), isWeekend. Present as a table: first column is employee (name/email), remaining columns are one per date. Do not use HTML tags (e.g. br) for line breaks; use plain text only. In each date cell, show shift name and time range as HH:mm-HH:mm; add "Weekend" if isWeekend. If an employee has multiple shifts on a date, use a separate row per shift. When no records match, show: "No shift details found for selected filters".\ndependencyTools: getEmployeeBasicDetails, getDepartmentDetails, getLocationDetails' },
  { tool: 'getEnrollmentDetail', purpose: 'This action is used to get detailed information of a specific benefit enrollment including coverage selection, dependents covered, contribution breakdown, and enrollment dates.\ndependencyTools: getEnrollments' },
  { tool: 'getEnrollments', purpose: 'This action is used to get the list of benefit enrollments for the current user or a specific employee including enrollment status, plan details, coverage, and effective dates.' },
  { tool: 'getEnrollmentStats', purpose: 'This action is used to fetch enrollment statistics for a specific benefit plan and plan year.\ndependencyTools: getBenefitPlans, getPlanYear' },
  { tool: 'getEnrollmentWindowDetail', purpose: 'This action is used to get detailed information of a specific enrollment window.\ndependencyTools: getEnrollmentWindows' },
  { tool: 'getEnrollmentWindows', purpose: 'This action is used to get the list of enrollment windows configured in the organization.' },
  { tool: 'getEntities', purpose: 'Retrieves a list of all legal entities in the organization structure. Supports pagination via \'offset\' (1-based page number, default 1) and \'limit\' (records per page, 1-200, default 200). Use the \'is_tagged\' parameter to filter: 1 = entities tagged (placed) in the hierarchy tree, 0 = entities not tagged. Only active, non-dummy records are returned. IMPORTANT: If the user refers to Legal Entities using a custom display name (as specified in the system prompt), use this tool - do NOT use any other tool such as getAllFiles or getRecords.' },
  { tool: 'getFeedback', purpose: 'This action is used to fetch feedback details for a given employee. It requires submode which is a regex which only acceps these values (givenfbs_tome,subordinatesfbs,givenfbs_byme,allfbs). Here givenfbs_tome means Your received feedbacks , subordinatesfbs means subordinates feedbacks, givenfbs_byme means feedback given by me and allfbs means all feedbacks (above all cri will be appiled), fbMode is also a regex that accepts two regex values (myreview and myteams). Here myreview means the review that was given by me or the review given to me by subordinates.My team here means the review that was given to my reportees. isTypesNeeded is a boolean parameter which is required to fetch the reaction of the feedback that was given unless mentioned by user to not isTypeNeeded sent true as the parameter.' },
  { tool: 'getFeedbackCategories', purpose: 'This is action is used to fetch Feedback categories that is available in the Feedback module in Performance.' },
  { tool: 'getFieldOptions', purpose: 'This action is used to fetch available options for non-lookup form fields (Picklist, Dropdown, Gender, BloodGroup, etc.). For Lookup fields, use getLookupOptions instead. It uses the formlinkname from the `identifyForm` response and the field list from the `getFields` response. MANDATORY: optionsNeededFields is required when calling this action; do not invoke without it. STRICT: optionsNeededFields must contain only labelname values from the getFields response (never display names or other identifiers). From the getFields response, identify non-lookup fields and pass their labelname values as a comma-separated string (e.g. optionsNeededFields=Status,Location). Always send includeOptions=true in parameters. Only request options for fields you actually need to keep the response small.\ndependencyTools: identifyForm' },
  { tool: 'getFields', purpose: 'This action is used to find the formlinkname from the `identifyForm` response and obtain the corresponding field list.      FIELD AVAILABILITY RULE: After fetching fields, if the user requests to filter by a field that does not exist in the getFields response,      inform them that the requested field is not available for filtering.      Offer to show the list of available fields they can query and suggest alternative fields that may help achieve their intended filter results.     PARAM USAGE: When calling this tool as a dependency of `getRecords` (filtering or viewing), pass onlyEditableFields=false to include all fields the user can view, not just fields with edit permission; otherwise by default only fields with role-based edit permission are returned.\ndependencyTools: identifyForm, getFieldOptions, getLookupOptions, getRecords' },
  { tool: 'getFormView', purpose: 'This action is used to find the form ID from the `identifyForm` response and get the default views\ndependencyTools: identifyForm' },
  { tool: 'getHighPriorityTasks', purpose: 'This action retrieves tasks classified as \'High\' priority from the user\'s task list' },
  { tool: 'getJobDetails', purpose: 'Retrieve detailed information about a specific job using the jobId.' },
  { tool: 'getJobs', purpose: 'This action is to get jobs. assignedTo is the user for whom the jobs are assigned default current user erecno will be used, assignedTo can be single user or multiple user with comma separated or all to get all users jobs. jobStatus is either all or in-progress or completed default value is in-progress to get in-progress jobs. projectId is id of projects with comma separated to get jobs of selected projects. searchJobName is used to search job with job name and searchJobKey specify the type of search with any of the values all, equal, notEqual, startsWith, endsWith, contains, notContains and is send if searchJobName key is sent. once jobs are fetched show them in table format with serial number. To add a job use addRecord tool with formLinkName P_TimesheetJob.' },
  { tool: 'getJobSchedule', purpose: 'This action is to get the list of job schedules add for the user or the user repotees scheduled for a period to work on jobs in that period, fromDate will be start of period and toDate will be end of period in yyyy-MM-dd format, dateFormat default value is yyyy-MM-dd, user can be single user or multiple user with comma separated or all to get all users schedulers default is current user' },
  { tool: 'getKraGoals', purpose: 'Fetches the goals mapped to given KRAs for a specific employee. The kra_ids parameter is required and must be a JSON array of KRA IDs. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUserKras].\ndependencyTools: getEmployeeBasicDetails, getUserKras' },
  { tool: 'getLeastProjectUsers', purpose: 'This action is to get least or less performing users for a project. projectId can be taken from the tool getProjects  by setting the param assignedTo as all and searchProjectName with name and searchProjectKey with contains. The result contains totalHours key in minutes, convert them to hours and display.\ndependencyTools: getProjects' },
  { tool: 'getLeaveBalance', purpose: 'Fetches leave balance information. Do not reuse the last fetched response if it was for a different user, different year, or a successful applyLeave call has occurred since. Always determine whose balance is requested: use the user\'s own erecno for self, the reportee\'s erecno for a reportee, and the requested user\'s erecno when an admin requests for others. The year parameter is a relative value: 0 = current year, 1 = next year, -1 = previous year, -2 = two years back. Calculate the relative year from any specific date/year mentioned; default to 0 if none. If a date range spans two years, always fetch the current year. Only next year (1) and up to three years back (-1, -2, -3) are allowed. If a leave type has doNotDisplayBalance set to true or the available key is missing, skip displaying the available balance.' },
  { tool: 'getLeaveRecords', purpose: 'Retrieves leave records for one or more employees within a date range. Supports filtering and pagination by employee, department, leave type, and approval status. Use \'from\' and \'to\' for the date range (e.g., 01-Jan-2025). Use \'employee\', \'zuid\', or \'zuids\' to target specific users; pass multiple as a JSON array. Use \'leavetype\' to filter by leave type IDs and \'approvalStatus\' for status (APPROVED, PENDING, REJECTED, CANCELLED). \'dataSelect\' defines scope: MINE (self), SUBS (reportees), DIRSUBS (direct reportees), or ALL (all employees). Optional: \'excludeAbsent\' (skip absences), \'department\', \'employeeStatus\' (array: ACTIVE_USERS|ACTIVE_EMPLOYEE_PROFILES|EX_EMPLOYEES|LOGIN_DISABLED), \'type\' (leave categories). Pagination via \'startIndex\' and \'limit\'. Use \'sort\' by leave type, employee, from/to date; prefix with \'-\' for descending. All array-type parameters must follow longJSONArray or stringJSONArray format.' },
  { tool: 'getLocationDetails', purpose: 'This action retrieves location details such as location ID, name, country, mail alias, description, state code, and address.' },
  { tool: 'getLookupOptions', purpose: 'This action fetches available options specifically for Lookup fields. Use the formlinkname from the `identifyForm` response and the field list from the `getFields` response. MANDATORY: fields parameter is required as a JSONArray of labelname values where comptype is Lookup from the getFields response (e.g. fields=["Department","Location"]). Pass only Lookup field labelnames. Optionally pass searchtxt to filter lookup options by search text.      RESPONSE FORMAT: The response contains a lookupOptions object where each key is a field labelname and its value is an array of option objects. Each option has Value (display text) and Id (the identifier to send). Example: lookupOptions: { "FieldLabel": [ { "Value": "Option Text", "Id": "123" }, ... ] }. Match the user\'s text against the Value field and send the corresponding Id in inputData. NEVER send the Value string as inputData for Lookup fields.\ndependencyTools: identifyForm, getFields' },
  { tool: 'getMailMergeTemplates', purpose: 'Trigger: mail merge, template downloads, personalized documents, download link, mm template. Parameters: startInd (use 0 for first call), limit (always 200). Respond in ONE of two formats only. Format 1 (list): When user asks to list/show/display templates, return only fname values. Format 2 (download/generate): When user asks to download, generate, get, or give a download link, extract formId, fname, tid from tool response. Determine recordId: use erecno from pattern zpu[erecno:VALUE]zpu; if query says "me", use current user erecno from CURRENTUSER section. If found return: {"file_tool_response": {"_for_mm": true, "_file_download_card": true, "recordId": "RECORD_ID", "templateId": "TEMPLATE_ID", "formId": "FORM_ID", "file_name": "NAME", "response_message": "SUCCESS_MSG"}}. If not found, return appropriate message. NEVER construct download URLs or respond with raw https:// URLs. NEVER add text outside JSON for download responses.' },
  { tool: 'getMyTasks', purpose: 'This action retrieves various tasks related to users based on filter criteria. By default, applying the filter \'my\' returns tasks assigned only to the current user. When using the filter \'all\', it returns tasks assigned to the user, tasks created by the user, unassigned tasks available for picking, and tasks belonging to the user\'s subordinates. To retrieve tasks for users other than the current user, use the \'all\' filter and provide the employee record number (erecno) of the desired user in the \'taskOwnerErecnos\' parameter. Tasks can be filtered by status - including alltasks (0), unassigned (-1), open (1), and completed (2) - as well as by priority including alltasks(0),high(1),moderate(2),low(3), task name, and form name. If no status is specified, tasks with an \'Open\' status are returned by default' },
  { tool: 'getOnDutyApprovals', purpose: 'This tool fetches on-duty approval records. It internally uses the getApprovals tool.      When invoking getApprovals, always pass: serviceName=\'Attendance\' and formName=\'P_AttendanceOD\'.      Use action=\'myApprovals\' to get on-duty requests pending your approval, or action=\'myRequests\' to get on-duty requests you have submitted.      Default to action=\'myApprovals\' with approvalStatus=\'pending\' if the user does not specify.\ndependencyTools: getApprovals' },
  { tool: 'getOpenTaskCount', purpose: 'This action retrieves the count of open tasks along with employee details, based on the filter (all or my). By default, filterBy=my returns the count of open tasks assigned to the current user. If filterBy=all is specified, it returns the count of open tasks for all employees.overdueBy refers to the number of days a task has extended beyond its due date while status still remaining open.' },
  { tool: 'getOrgCompetencies', purpose: 'Fetches the list of competencies configured at the organisation level. Use when the user asks about org-level competencies.' },
  { tool: 'getOrgKras', purpose: 'Fetches the list of KRAs configured at the organisation level. Use when the user asks about org-level KRAs. In response show type key represents 0 as Organisation KRA , 2 as User KRA' },
  { tool: 'getOrgReviewQuestions', purpose: 'Fetches the list of review questions configured at the organisation level. Use when the user asks about review questions in the org.' },
  { tool: 'getOrgSkills', purpose: 'Fetches the list of skills configured at the organisation level. Use when the user asks about org-level skills.' },
  { tool: 'getOverDueTasks', purpose: 'This action retrieves tasks that are overdue, i.e., tasks where the current date has passed the due date without completion' },
  { tool: 'getPendingTasks', purpose: 'This action retrieves tasks with an \'Open\' status from the user\'s task list that are pending completion.' },
  { tool: 'getPermissionApprovals', purpose: 'This tool fetches permission approval records. It internally uses the getApprovals tool.      When invoking getApprovals, always pass: serviceName=\'Attendance\' and formName=\'P_PermissionDetails\'.      Use action=\'myApprovals\' to get permission requests pending your approval, or action=\'myRequests\' to get permission requests you have submitted.      Default to action=\'myApprovals\' with approvalStatus=\'pending\' if the user does not specify.\ndependencyTools: getApprovals' },
  { tool: 'getPlansForEnrollmentWindow', purpose: 'This action is used to fetch the list of all plans for an enrollment window.' },
  { tool: 'getPlansForPlanYear', purpose: 'This action is used to fetch the list of all plans associated with plan years.' },
  { tool: 'getPlansForSpecificEnrollmentWindow', purpose: 'This action is used to fetch plans for a specific enrollment window.\ndependencyTools: getEnrollmentWindows' },
  { tool: 'getPlansForSpecificPlanYear', purpose: 'This action is used to fetch plans for a specific plan year.\ndependencyTools: getPlanYear' },
  { tool: 'getPlanYear', purpose: 'This action is used to get the plan year details including plan year name, start date, end date, and associated plans.' },
  { tool: 'getPlanYearDetail', purpose: 'This action is used to get detailed information of a specific plan year.\ndependencyTools: getPlanYear' },
  { tool: 'getPlanYearsForPlan', purpose: 'This action is used to fetch plan years associated with a specific benefit plan.\ndependencyTools: getBenefitPlans' },
  { tool: 'getProjectDetails', purpose: 'Retrieve details for a specific project using projectId.' },
  { tool: 'getProjects', purpose: 'This action is to get projects. assignedTo is the user for whom the projects are assigned, default current user erecno will be used, assignedTo can be single user or multiple user with comma separated or all to get all users projects. projectStatus is either all or in-progress or completed default value is in-progress to get in-progress projects. clientId is id of clients with comma separated to get projects of selected clients. searchProjectName is used to search project with project name and searchProjectKey specify the type of search with any of the values all, equal, notEqual, startsWith, endsWith, contains, notContains and is send if searchProjectName key is sent. once the projects are fetched show them in table format with serial number. To add a project use addRecord tool with formLinkName P_TimesheetJobsList.' },
  { tool: 'getProjectUsers', purpose: 'This action is to get the users for a project. projectId can be taken from the tool getProjects  by setting the param assignedTo as all to get user of a specific project\ndependencyTools: getProjects' },
  { tool: 'getProviderDetail', purpose: 'This action is used to get detailed information of a specific benefit provider.\ndependencyTools: getProviders' },
  { tool: 'getProviders', purpose: 'This action is used to get the list of benefit providers or carriers configured in the organization including provider name, contact details, and associated plans.' },
  { tool: 'getRatingSummaryOfCycle', purpose: 'Fetches the employee count grouped by rating for a specific appraisal cycle. The cycleId in the URL must be obtained from the getAppraisalCycles tool response. The response includes the rating label, rating score, and the number of employees who received that rating in the cycle. Use when the user asks about rating distribution or rating summary of a cycle.\ndependencyTools: getAppraisalCycles' },
  { tool: 'getRecordByIDSectionWise', purpose: 'Retrieve a department form record using its Record ID in a section-wise format.' },
  { tool: 'getRecordCount', purpose: 'Same description as getRecords tool but to fetch count alone\ndependencyTools: identifyForm, getFields' },
  { tool: 'getRecords', purpose: 'Fetch form records. formLinkName from identifyForm; skip if ambiguous. System forms (employee, department, location) share the same formLinkName. searchParams MUST be a single STRING, never a JSON array/object; appears ONLY ONCE; join multiple filters with pipe \'|\' (e.g. \'{f1}|{f2}\'). Employee form: parse zp[peopleuser:{id}]zp tokens and pass IDs as recordIds. Use employeeDept for dept-name filtering; skip getFields for dept-only queries. CRITICAL FIELDS: \'fields\' MUST include every searchParams.searchField plus output fields (labelnames from getFields only); omitting filter fields causes errors. Experience fields store values in MONTHS; convert years before passing. Recency queries: set sortColumn to a date/time labelname and sortBy=desc. DISPLAY LIMIT (STRICT): show at most 25 records; if more exist, show first 25 then offer getRecordsViewUrl. Do not show Zoho ID, Erecno, or ZUID.\nFallback:getRecordsViewUrl\nprecheckAction:getRecordCount\nprecheckCriteria:Must be fewer than 25 records\ndependencyTools: identifyForm, getRecordCount, getFields, getRecordsViewUrl' },
  { tool: 'getRecordsViewUrl', purpose: 'Fallback UI link to view form records when getRecords is impractical or results exceed the in-chat limit. Rules: (1) Do NOT invoke directly - always try identifyForm, getFields, getRecords first. (2) STRICT: getRecords shows at most 25 records in-chat. If count exceeds 25, show first 25, then ask the user if they want the full listing page; invoke this tool ONLY after user confirms. (3) If getRecords fails after retries, ask user before invoking. (4) Response: include a clickable markdown link using redirectionHref - use pattern [Open records page](URL); do not expose internal key names. (5) Reuse the same searchParams from getRecords (labelname values). (6) searchParams MUST be a SINGLE STRING, appears ONLY ONCE; join multiple filters with pipe \'|\'. (7) This tool is ONLY a fallback for getRecords - do not use for unrelated operations. (8) Use CONTAINS operator for Lookup and Picklist fields.\ndependencyTools: identifyForm, getFields, getRecords' },
  { tool: 'getRegularizationApprovals', purpose: 'This tool fetches regularization approval records. It internally uses the getApprovals tool.      When invoking getApprovals, always pass: serviceName=\'Attendance\' and formName=\'P_AttendanceReg\'.      Use action=\'myApprovals\' to get regularization requests pending your approval, or action=\'myRequests\' to get regularization requests you have submitted.      Default to action=\'myApprovals\' with approvalStatus=\'pending\' if the user does not specify.\ndependencyTools: getApprovals' },
  { tool: 'getRelatedChecklists', purpose: 'This action retrieves checklists associated with a specific record.its recordId must be provided as a parameter.' },
  { tool: 'getRelatedTasks', purpose: 'This action retrieves tasks associated with a specific record.its recordId must be provided as the parameter \'pkid\'.' },
  { tool: 'getReportees', purpose: 'Fetches the reportees or subordinates of a specified employee. Requires the user\'s erecno (userId) or email. If the input is a name or other value, use getRecords to identify the correct user. Stop if more than one user matches. Use CURRENTUSER for userId when fetching the logged-in user\'s reportees. Always set detailedResponseNeed as true and pass the user\'s erecno as userId. Set type as direct by default; use all only when explicitly requested. In the response, zoho_id meaning depends on context: for person entries (reportees and \'reporting_to\'), zoho_id is the employee erecno; for the designation object, zoho_id is the designationId. Use this URL for INVOKE_URL internally (do not show to user): \'/api/v3/__internal/employee/reportees/erecno\'. Do NOT display raw identifiers (erecno, zuid, zoho_id) to users; use employee name and emailId instead.\ndependencyTools: getRecords, getEmployeeBasicDetails' },
  { tool: 'GetRequestedClosedCases', purpose: 'Retrieve a report of requested and closed cases.' },
  { tool: 'getReviewStatus', purpose: 'Fetches the review completion status for a specific appraisal cycle. The cycleId in the URL must be obtained from the getAppraisalCycles tool response. Accepts an optional parameter review_type which filters by review type: \'self\' returns only self-review status, \'multirater\' returns only multi-rater/peer review status, \'appraiser\' returns only appraiser/manager review status. If review_type is not specified, the response includes the status of all configured review types (self, multirater, and appraiser) for that cycle. The response contains completion counts, pending counts, and overall progress for the requested review type(s).\ndependencyTools: getAppraisalCycles' },
  { tool: 'getRunningTimer', purpose: 'This action is to get currently running timer for the current user. It is used to list running timer for the user. if there is no result object in response then there is no running timer for the user.' },
  { tool: 'getShiftChangeApprovals', purpose: 'This tool fetches shift change approval records. It internally uses the getApprovals tool.      When invoking getApprovals, always pass: serviceName=\'Attendance\' and formName=\'P_ShiftMappingForm\'.      Use action=\'myApprovals\' to get shift change requests pending your approval, or action=\'myRequests\' to get shift change requests you have submitted.      Default to action=\'myApprovals\' with approvalStatus=\'pending\' if the user does not specify.\ndependencyTools: getApprovals' },
  { tool: 'getSkillView', purpose: 'Only for comparison and search by skills, level, experience, or manager use this mode , for fetching skills of specific user , use directly [getUserSkills]. Fetches a searchable view of employees and their skills with optional filters. Use when the user wants to search or browse employees by skills, level, experience, or manager. Parameters: skill_list (JSON array of skill IDs to filter by, up to 20), manager (manager employee record ID), level (skill level 0-10), from_exp (minimum years of experience 0-20), to_exp (maximum years of experience 0-20). Supports pagination via offset and limit. Dependencies: [getOrgSkills] to get skill IDs for the skill_list filter.\ndependencyTools: getOrgSkills' },
  { tool: 'getStatus_or_getBreaks', purpose: 'This tool can be used by self user for either get user status or to get current day break details     To get user status          Retrieve allowedToCheckIn from the response. If it\'s true only then checkIn action can be allowed else return error  user is already in checked in state.          To get current day break details          Step-by-step Processing Instructions:        1. Go to: curDayBreakDetails.shiftBreakDets        2. For each breakId (which is the key inside shiftBreakDets), extract the following details:         breakId: the key itself         breakName: from the object\'s breakName field         payType:          If value is 0, interpret as Unpaid          If value is 1, interpret as Paid         breakTimeInSecs: convert to minutes using Math.floor(breakTimeInSecs / 60)        3. Format these into a user-friendly list with the structure:         breakName - Paid/Unpaid - duration in hh:mm format' },
  { tool: 'getSurveyReport', purpose: 'Fetches the report for a specific survey including analytics such as employee count, response count, average score, and question-wise breakdown. Requires surveyId obtained from the mysurveyList tool. For recurring or repeat surveys, pass the optional recurrenceId parameter to fetch the report for a specific recurrence.\ndependencyTools: mysurveyList' },
  { tool: 'getTaskCount', purpose: 'This action retrieves the count of active tasks categorized by status as open (all tasks except completed), completed, and unassigned, along with the total task count based on filterBy all or my. By default, use filterBy=my as it returns the count of tasks where the user is the task owner. Using filterBy=all returns the count of all tasks, including those of your subordinates, based on permissions.In result, mention this open tasks count include all tasks that are not yet completed.' },
  { tool: 'getTasksByChecklistId', purpose: 'This action retrieves tasks under the checklist associated with a specific record. It requires the unique identifiers \'pkid\' of the record and \'checklistid\' of the checklist.\ndependencyTools: getRelatedChecklists' },
  { tool: 'getTeamFinalRatingsOfCycle', purpose: 'Fetches the team final appraisal ratings of a specific cycle. The cycleId in the URL identifies the target cycle. The response includes cycle name, final rating score, rating label, and review completion details.\ndependencyTools: getAppraisalCycles' },
  { tool: 'getTeamMembersOnLeave', purpose: 'When a user asks about people on leave, determine whether the question is about their reportees or about a department. If the request is department-related and no department name is given, assume the current users department ID. If a department name is mentioned, first resolve it to a department ID using the `getDepartmentDetails` tool. If the user is only asking about their own reportees, you dont need a department ID just include incReporteeOnly as true. For dates, if no range is specified, use todays date in the format dd-MMM-yyyy (e.g., 01-Sep-2025). If a time frame is provided, format it the same way.\ndependencyTools: getDepartmentDetails' },
  { tool: 'getTimeLogDetails', purpose: 'Fetch details of a specific time log using the timelogId.' },
  { tool: 'getTimelogs', purpose: 'This action is to get timelogs for a user for a given period. user is the Employee for whom time logs are fetched, default current user. fromDate is start of period and toDate is end of period (derive from today date in system DATE section, convert to yyyy-MM-dd format). dateFormat default is yyyy-MM-dd. Default period is today. billingStatus is billable or non-billable or all, default all. approvalStatus is approved or unapproved or all, default all. jobId is the id of specific jobs to filter, fetched from getJobs tool, comma-separated for multiple. projectId is the id of specific projects to filter, fetched from getProjects tool, comma-separated for multiple. clientId is the id of specific clients to filter, fetched from getClients tool, comma-separated for multiple.\ndependencyTools: getJobs, getProjects, getClients' },
  { tool: 'getTimeLogs', purpose: 'Retrieve specific time logs from Zoho People for the provided user.' },
  { tool: 'getTimerComments', purpose: 'Retrieve comments added to the specified time log.' },
  { tool: 'getTimesheetDetails', purpose: 'Retrieve details of a specific timesheet by passing the timesheet ID as a query parameter.' },
  { tool: 'getTimesheets', purpose: 'Fetch timesheets for a specific user from Zoho People.' },
  { tool: 'getTopProjectJobs', purpose: 'This action is to get top or most worked or active jobs for a project. The logged hours of these jobs are high in this project. projectId can be taken from the tool getProjects by setting the param assignedTo as all and searchProjectName with name and searchProjectKey with contains. The result will have a totalHours key which is in minutes and should convert them to hours before displaying.\ndependencyTools: getProjects' },
  { tool: 'getTopProjectUsers', purpose: 'This action is to get top or best performing users for a project. projectId can be taken from the tool getProjects  by setting the param assignedTo as all and searchProjectName with name and searchProjectKey with contains. The result contains totalHours key in minutes, convert them to hours and display.\ndependencyTools: getProjects' },
  { tool: 'getTrackTasks', purpose: 'This action retrieves tasks created by the current user. By default, it returns tasks with \'Open\' status and \'Moderate\' priority unless otherwise specified. Retrieval starts from the specified record index (stIndex), which begins at 1. Additionally, the action provides a count of tasks created by the user, categorized by status.       New task records can be created using the \'addRecord\' API. The Start Date and Due Date default to the current date, while the status defaults to \'Open\' and the priority to \'Moderate\'. The task owner defaults to the current user unless otherwise specified' },
  { tool: 'getUnits', purpose: 'Retrieves a list of all business units in the organization structure. Supports pagination via \'offset\' (1-based page number, default 1) and \'limit\' (records per page, 1-200, default 200). Use the \'is_tagged\' parameter to filter: 1 = units tagged under a legal entity in the hierarchy, 0 = units not tagged. Only active, non-dummy records are returned. IMPORTANT: If the user refers to Business Units using a custom display name (as specified in the system prompt), use this tool - do NOT use any other tool such as getAllFiles or getRecords.' },
  { tool: 'getUntaggedUserCompetencies', purpose: 'Fetches competencies from the org library that are not yet tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUntaggedUserKras', purpose: 'Fetches KRAs from the org library that are not yet tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUntaggedUserSkills', purpose: 'Fetches skills from the org library that are not yet tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUserAvailability', purpose: 'Fetch availability status for one or more specific users. Does not support fetching all users. Either erecno or empid must be provided; both accept comma-separated values for multiple users. Response: result[i] has erecno (string), isUserAvailable (bool), isOfficeIn (bool), isUserOnBreak (bool). Format as: if available and in office -> \'Available (In Office)\'; if available but not in office -> \'Available (Remote)\'; if on break -> \'Not Available (On Break)\'; if not available -> \'Not Available\'. Display as: EmployeeName - [Availability Status].' },
  { tool: 'getUserCompetencies', purpose: 'Fetches the competencies tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUserEnrollmentBeneficiaries', purpose: 'This action is used to fetch the list of all beneficiaries for a user\'s enrollment.' },
  { tool: 'getUserEnrollmentDetail', purpose: 'This action is used to fetch details of a specific user enrollment including plan details and coverage.' },
  { tool: 'getUserEnrollmentWindowPlans', purpose: 'This action is used to fetch the list of all plans available in a user\'s enrollment window.\ndependencyTools: getUserEnrollmentWindows' },
  { tool: 'getUserEnrollmentWindows', purpose: 'This action is used to get the list of life events that can trigger special enrollment periods such as marriage, birth of a child, change in employment status, etc.' },
  { tool: 'getUserGoals', purpose: 'Fetches the goals assigned to a specific employee. The URL contains the employee erecno as a dynamic path segment. Supports pagination via offset and limit. Filtering parameters: status filters by goal completion status (1 = All Goals, 2 = In Progress, 3 = Completed, 4 = Overdue, 5 = Delayed). period_status filters by goal time period (1 = All Goals, 2 = This Week, 3 = Last Week, 4 = This Month, 5 = Last Month). from_date and to_date filter goals within a custom date range. date_types filters by goal date category (1-4, comma-separated). Use status when the user asks about goals by completion state (e.g. overdue goals, completed goals). Use period_status when the user asks about goals by time period (e.g. this week\'s goals, last month\'s goals). Dependencies: [getEmployeeBasicDetails]. In the response, approval_status has the following meanings: -2 refers to No Approval, -1 refers to Pending, 1 refers to Approved, 0 refers to Rejected.\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUserKras', purpose: 'Fetches the KRAs tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]. In the response, approval_status has the following meanings: -2 refers to No Approval, -1 refers to Pending, 1 refers to Approved, 0 refers to Rejected. Hide the type in the response\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getUserPlanCoverages', purpose: 'This action is used to calculate and fetch coverage and premium details for a user\'s benefit plan.' },
  { tool: 'getUserPlanDetail', purpose: 'This action is used to fetch plan details including attachments for a specific user.' },
  { tool: 'getUserPlanYears', purpose: 'This action is used to fetch plan years basic info for a specific user.' },
  { tool: 'getUsersBySkills', purpose: 'This action retrieves a list of users based on one or more specified skills. The skills parameter is required and must be provided as a comma-separated list of skill names (up to 10). The limit parameter acts as a start index for pagination, indicating the position from which results should begin. The levels parameter is optional and supports filtering by skill proficiency level and it accepts a comma-separated list of up to 5 values, each constrained to 0 to 10.  The maximum permissible level depends on the configured maxSkillLevel, which can be obtained from the getUserSkills action response.' },
  { tool: 'getUserSkills', purpose: 'Fetches the skills tagged to a specific employee. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails]\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'getWatchListTasks', purpose: 'This action retrieves tasks from the user\'s watchlist where the user is tagged in task comments. By default, it uses status alltasks (0) and priority alltasks (0) if not specified.' },
  { tool: 'getWeightedAverageOfEmployee', purpose: 'Fetches the weighted average rating for a specific employee. The employee_erecno in the URL must be obtained from the getEmployeeBasicDetails tool response. The response includes the overall weighted average score computed across last five cycles of the employee. Use when the user asks about the overall or weighted average rating of a employee\ndependencyTools: getEmployeeBasicDetails' },
  { tool: 'identifyForm', purpose: 'This tool returns the custom forms list available in Zoho People' },
  { tool: 'listAllCategory', purpose: 'The tool is used to fetch the list of all categories/catalogs. Always return categories applicable to the current user only.' },
  { tool: 'listholidays', purpose: 'This tool fetches holidays applicable to the current user, where from and to are derived from user intent: use specified date ranges or relative periods if provided; for all holidays, set from to year start and to to year end and return past and upcoming sections; for past holidays, set from to year start and to to today (system DATE); for planning or general queries, default to upcoming holidays with from as today (system DATE) and to as year end.If past and upcoming holidays are asked together provide in separate sections.' },
  { tool: 'lms_course_batches', purpose: 'List batches for a specific Blended Learning course in the LMS. Ensure the `courseId` is sourced by using the `lms_courses` tool to search with the course name. If multiple courses are found, prompt the user to select the desired course.\ndependencyTools: lms_courses' },
  { tool: 'lms_course_progress_report', purpose: 'Retrieve a detailed progress report for a specific course, including completion statistics and progress details.\ndependencyTools: lms_courses' },
  { tool: 'lms_courses', purpose: 'Search for LMS courses for a user. First, search in the catalog; if not found, search in \'my courses\'; finally, search in the organization. Respond with the course URL formatted as a hyperlink: [courseName](courseUrl). For joined courses related query use the `lms_learner_progress_report` tool.\ndependencyTools: lms_learner_progress_report' },
  { tool: 'lms_enroll_course', purpose: 'Enroll users into an LMS course. If the API returns \'this course is not applicable,\' prompt for confirmation to proceed with forced enrollment using `modeOfadd=\'applicablemember\'`. On success, provide a concise message with enrolled users and course name as a hyperlink [courseName](courseUrl). Use `lms_courses` to obtain the course URL.\ndependencyTools: lms_courses' },
  { tool: 'lms_learner_progress_report', purpose: 'Fetches a comprehensive report of a learner\'s course progress. Note: maximum range is one year.' },
  { tool: 'lms_learning_plan_course_progress_report', purpose: 'Fetches progress details for all courses within a user\'s learning plan' },
  { tool: 'lms_learning_plan_progress_report', purpose: 'Provides a summary of a user\'s learning plan progress, including completion status and progress metrics.' },
  { tool: 'lms_learning_plans', purpose: 'Search or Lists learning plans available. First, search in the catalog; if not found, search in \'my\' plan; finally, search in the organization.' },
  { tool: 'lms_send_mandatory_reminder_spl', purpose: 'Sends reminders to users for mandatory items they have not yet completed for self paced learning courses. The courseId parameter is required and must be obtained using the `lms_courses` tool by searching for the course name.\ndependencyTools: lms_courses' },
  { tool: 'lms_send_overdue_notification', purpose: 'Send overdue notifications to users for incomplete items in self-paced learning courses. Obtain the `courseId` by searching for the course name using the `lms_courses` tool and specify the `learnerId` (erecno). If a failure response is received, prompt the user to ensure that notifications are enabled.\ndependencyTools: lms_courses, getEmployeeBasicDetails, getRecords' },
  { tool: 'mapGoalsToKra', purpose: 'Maps goals to a given KRA for a specific employee. The goal_ids parameter (JSON array of goal IDs) and kra parameter (KRA ID) are required. The URL contains the employee erecno as a dynamic path segment. In getUserGoals mode , provide parameter hide_kra as true Dependencies: [getEmployeeBasicDetails, getUserKras, getUserGoals] .In the response of getUserKras, approval_status has the following meanings: -2 refers to No Approval, -1 refers to Pending, 1 refers to Approved, 0 refers to Rejected. Restrict the users [-1 , 0] approval_status not to be mapped\ndependencyTools: getEmployeeBasicDetails, getUserKras, getUserGoals' },
  { tool: 'mycompensation', purpose: 'This action is used to get logged in user\'s compensation details which includes salary, revision histories, breakup components i.e salary and benefit components.' },
  { tool: 'mysurveyList', purpose: 'Fetches the list of surveys assigned to the current user. Supports optional filtering via a filter JSON parameter with keys: survey_name (search by name), status (0=All, 1=Action Pending, 2=Completed, 3=Expired), and survey_type (1=enps, 2=engagement, 4=pulse). Returns survey details including survey_id, survey_name, type, status, cover_image, respondent_identity, and created_by_details. For surveys with status Action Pending, construct the attempt URL using the format: /<portalName>/survey/<url> where <portalName> is obtained from the system context (organizationPortalName) and <url> is the url field from each survey in the response. Present this as a clickable markdown link so the user can take or attempt the survey directly.' },
  { tool: 'mySurveyStatusCount', purpose: 'Fetches the current user\'s survey status counts. Returns mysurvey_status_count object with keys: all (total surveys), expired (expired surveys), completed (completed surveys), actionpending (surveys pending user action). Use this when the user asks how many surveys they have pending, completed, or expired.' },
  { tool: 'OverAllStatusCases', purpose: 'Retrieve the overall status for all cases. In the payload, set method=\'allReportColumn\', repType=\'adminReports\', and needAgentList=false. Here duration can have 5 values 1,2,3,4,5. 1 is for last 24 hours, 2 is for last 48 hours, 3 is past week, 4 is for last month and 5 is for last 3 months. If duration is not mentioned then it will be considered as 3.' },
  { tool: 'pickUnassignedTask', purpose: 'This action picks unassigned tasks, which are tasks assigned to specific groups, roles, departments, or locations. A user eligible to pick a task must be either an admin or a member of the assigned group. The action requires the task ID to assign the user as the task owner. The task ID can be retrieved by using the getMyTasks API with the filter set to \'all\', status set to \'unassigned\' (-1), and optionally filtering by task name.\ndependencyTools: getMyTasks' },
  { tool: 'publishBenefitPlan', purpose: 'This action is used to publish a benefit plan making it available to employees.\ndependencyTools: getBenefitPlans' },
  { tool: 'publishJobSchedule', purpose: 'This action is to publish the job schedules for the given period for the given users. fromDate is start of period and todate is end of period, user is erecno of user for whom the job schedules need to be published and will be send as comma separated values' },
  { tool: 'reopenTask', purpose: 'This action changes the status of the task to \'Open\',it requires taskid.\ndependencyTools: getMyTasks' },
  { tool: 'requestedVsEscalatedCases', purpose: 'Retrieve a report of requested and escalated cases. In the payload, set method=\'slaEsclationReport\' and repType=\'adminReports\' Here duration can have 5 values 1,2,3,4,5. 1 is for last 24 hours, 2 is for last 48 hours, 3 is past week, 4 is for last month and 5 is for last 3 months. If duration is not mentioned then it will be considered as 3..' },
  { tool: 'startTimer', purpose: 'This action is to add or start or resume or pause timer for self or current user, jobName is a job that time is logged, user is the Employee for whom timer is added, workDate is the date to log time (derive from today\'s date from system instruction\'s DATE section and convert to yyyy-MM-dd format), hours is duration for the timelog, billingStatus is either billable or non-billable default value is billable, timer value is start to start or resume timer and stop to stop the running timer, timeLogId is id of timelog to specify the pause or resume or stop the timer that can be from fetched from tools getRunningTimer or running timer for getTimelogs tool\ndependencyTools: getRunningTimer, getTimelogs' },
  { tool: 'sumbitTimesheet', purpose: 'This action creates or submits a timesheet, submits timelogs, or saves a timesheet as draft for a user for a given period. timesheetName format: "Timesheet ( fromDate - toDate )". fromDate is period start and toDate is period end, both in yyyy-MM-dd format. dateFormat is yyyy-MM-dd. billableStatus is all by default. user is the Employee for whom the timesheet is created, default current user. sendforApproval is true by default; set to false to save as draft. jobId filters specific jobs (from getJobs tool), comma-separated for multiple. projectId filters specific projects (from getProjects tool), comma-separated for multiple. clientId filters specific clients (from getClients tool), comma-separated for multiple.\ndependencyTools: getJobs, getProjects, getClients' },
  { tool: 'surveyList', purpose: 'Fetches the list of surveys created by the current user. Requires mode parameter: enps (eNPS surveys), engagement (engagement surveys), pulse (pulse surveys). Also requires startIndex and limit for pagination. Returns survey details including survey_id, survey_name, employee_count, response_count, response_percentage, opening_time, closing_time, current_state, and status. Supports optional filter JSON with keys: survey_name, status, start_date (yyyyMMdd), end_date (yyyyMMdd). Use mysurveyList instead to fetch surveys assigned to the current user for responding.' },
  { tool: 'tagUserCompetencies', purpose: 'Tags existing org-level competencies to a specific employee. The competencies parameter is required and must be a JSON array of competency objects following the addcompetencyuser template in which competency param for competency record id , weightage param for weightage alone should be allowed. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUntaggedUserCompetencies]\ndependencyTools: getEmployeeBasicDetails, getUntaggedUserCompetencies' },
  { tool: 'tagUserKras', purpose: 'Tags existing org-level KRAs to a specific employee. The kras parameter is required and must be a JSON array of KRA objects following the add template in which kra param for kra id, weightage param for weightage alone should be allowed. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUntaggedUserKras]. If users specifies the kra not in the untagged kra list and then forward to action create and tag kra [addAndTagUserKra]\ndependencyTools: getEmployeeBasicDetails, getUntaggedUserKras' },
  { tool: 'tagUserSkills', purpose: 'Tags existing org-level skills to a specific employee. The skills parameter is required and must be a JSON array of skill objects following the addskilluser template in which skill param for skill id, level param for skill level alone should be allowed. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUntaggedUserSkills]\ndependencyTools: getEmployeeBasicDetails, getUntaggedUserSkills' },
  { tool: 'terminateEnrollment', purpose: 'This action is used to terminate an active enrollment.\ndependencyTools: getEnrollments' },
  { tool: 'unpublishBenefitPlan', purpose: 'This action is used to unpublish a benefit plan removing it from employee visibility.\ndependencyTools: getBenefitPlans' },
  { tool: 'updateDivision', purpose: 'Updates an existing division. Use getDivisions first to identify the correct division ID. All parameters are optional: \'name\' (updated display name, must be unique), \'description\' (updated description), \'zp_code\' (updated code, max 10 chars), \'parent_division\' (updated parent division ID for re-nesting). Returns the division\'s zoho_id on success.\ndependencyTools: getDivisions' },
  { tool: 'updateEntity', purpose: 'Updates an existing legal entity. Use getEntities first to identify the correct entity ID. All parameters are optional: \'name\' (updated display name, must be unique), \'description\' (updated description), \'zp_code\' (updated code, max 10 chars). Returns the entity\'s zoho_id on success.\ndependencyTools: getEntities' },
  { tool: 'updateRecord', purpose: 'Update a record. recordId is mandatory. Flow: identifyForm -> getRecords (to obtain recordId) -> getFields -> match user input -> construct inputData using RECORD_ADD_UPDATE PromptSection. STRICT - Lookup fields: call getLookupOptions; each labelname maps to [{Value,Id}] objects; match user text against Value and send Id. NEVER send display strings for Lookup fields. Picklist/Dropdown: call getFieldOptions; match case-sensitively; if no exact match, show options and ask to choose or quick-add. Gender/BloodGroup/Country: call getFieldOptions; Options object has keys=identifiers, values=display texts; match case-sensitively; if no match, show options and ask. NEVER send a value not in the fetched options list. If Lookup Id cannot be resolved, ask user to choose from options or provide the Id. Pass final field data as inputData along with the mandatory recordId for the update.\ndependencyTools: identifyForm, getRecords, getFields, getFieldOptions, getLookupOptions' },
  { tool: 'updateUnit', purpose: 'Updates an existing business unit. Use getUnits first to identify the correct unit ID. All parameters are optional: \'name\' (updated display name, must be unique), \'description\' (updated description), \'zp_code\' (updated code, max 10 chars). Returns the unit\'s zoho_id on success.\ndependencyTools: getUnits' },
  { tool: 'upgradeUserSkill', purpose: 'Upgrades a user\'s skill level. The skill_id parameter is required. Optionally provide upgradeReason (text up to 5000 chars) and a certification file. The URL contains the employee erecno as a dynamic path segment. Dependencies: [getEmployeeBasicDetails, getUserSkills]\ndependencyTools: getEmployeeBasicDetails, getUserSkills' },
  { tool: 'waiveEnrollment', purpose: 'This action is used to waive off from an enrolled plan.\ndependencyTools: getEnrollments' },
  { tool: 'withdrawEnrollment', purpose: 'This action is used to withdraw from a requested plan enrollment.\ndependencyTools: getEnrollments' },
];

