/* ─────────────────────────────────────────────
   Zoho Dataprep — Tool List Data
───────────────────────────────────────────── */

const DATAPREP_TOOLS = [
  { tool: 'Add_New_Connection', purpose: 'To create a new connection' },
  { tool: 'Add_Pipeline_to_Workspace', purpose: 'To create pipelines under specific projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'Create_New_Pipeline', purpose: 'To create pipelines' },
  { tool: 'Create_Workspace', purpose: 'To create projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'Delete_Workspace', purpose: 'To delete projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'Get_Pipeline_Import_Catalog', purpose: 'Initiates import or refresh of a pipeline\'s catalog information. This operation updates metadata about pipeline\'s data sources, schemas, and transformations. This is often required before running complex pipelines with the /run endpoint, especially for RELOAD, BACKFILL, or MANUAL_WITH_DATA run types.\n\nThe operation is asynchronous and returns a job ID that can be used to track progress. Upon completion, you can use the GET method of this endpoint to retrieve the updated catalog information including task IDs required for pipeline run configuration.\n\nYou can specify which connections to refresh by providing connection_ids, or set refresh_all=true to update all catalog information.' },
  { tool: 'getPipelineImportCatalog', purpose: 'Retrieves detailed information about a pipeline\'s extract/import tasks. This API is essential before using the /run or /schedule endpoints with RELOAD, BACKFILL, or MANUAL_WITH_DATA run types, as it provides the necessary task IDs and configuration details.\n\nThe response contains a pipeline object with a pipelinetasks array. Each task object contains:\n- id: The task ID to use as key in pipeline_run_config\n- type: Task type identifier (5=extract, 7=raw parse, 10=transform, 15=staged extract, 20=load/export, 25=code studio)\n- pipelinedatasource: Contains datasource configuration\n\nIn the pipelinedatasource.connection object:\n- connection.type=1: File datasource - use fetch_type="NO_DATA" (files don\'t need reload)\n- connection.type!=1: Database/API datasource - check datasource_details for incremental settings\n\nFor database/API datasources, check pipelinedatasource.datasource_details:\n- If fetch_incremented_data=true exists and is true, use fetch_type="IMPORT_ALL_DATA"\n- Otherwise, use fetch_type="IMPORT_SOURCE_FILE" for standard imports\n\nAll pipeline tasks from the response should be included in the pipeline_run_config when configuring run or schedule API calls. For each pipeline task, you must specify appropriate fetch configurations based on the connection type and incremental settings.' },
  { tool: 'getProject', purpose: 'To get projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'getSubscription', purpose: 'Retrieves subscription details including plan information, usage metrics, and remaining quotas. Returns comprehensive subscription data including plan name, plan ID, component limits (rowbatch, user, row, api, project, connector, destination, storage), addons purchased, usage counts, and expiry information. Essential for monitoring resource consumption and understanding current subscription limits.\n\nResponse includes:\n- Plan details: name, ID, components with limits\n- Addons: additional purchased components with totals\n- Usage count: current consumption metrics (rows processed, storage used, users, etc.)\n- Expiry information and status\n- Previous plan history\n\nFirst call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'loadDataset', purpose: 'Retrieves comprehensive metadata and sample data for a dataset. This endpoint provides detailed information about the dataset structure, column metadata, data types, quality metrics, and sample rows. To ensure the latest metadata is returned, call the /refresh endpoint before using this endpoint.\n\nResponse includes:\n- Dataset metadata: row count, column count, file size, data quality metrics\n- Column model: detailed information for each column including data types, constraints, quality metrics, and statistical information\n- Sample data: preview rows (excluding internal columns __zsid and __zsitime)\n- Data quality information: valid, invalid, and missing value counts\n- Statistical aggregates: min, max, average values for numeric columns\n- Discrete value distributions for categorical columns\n\nThe columnModel array contains metadata for each column:\n- displayName: User-friendly column name\n- dataType: Column data type with format information\n- widgets: Quality metrics, aggregates, and value distributions\n- pii: Personal data identification flags\n\nThe data array contains sample rows where the first array is headers and subsequent arrays are data rows. Internal columns (__zsid, __zsitime) are included in the response but should be filtered out in user interfaces.\n\nFirst call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'Re-authenticate_Connection', purpose: 'To reauthenticate the connection. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'refreshDataset', purpose: 'Refreshes the metadata of a dataset to ensure the latest information is available. This endpoint should be called before using the /load endpoint to get the most up-to-date dataset metadata. The refresh operation updates schema information, column details, and data quality metrics.\n\nUse this endpoint when:\n- Dataset structure may have changed at the source\n- Need to ensure latest metadata before loading\n- Data quality metrics need to be recalculated\n- Schema inference needs to be updated\n\nFirst call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'Remove_Pipeline_Schedule', purpose: 'Removes the schedule configuration for a pipeline. This stops any future automated executions of the pipeline. Previously completed runs are not affected. After deletion, you can create a new schedule using the POST method of this endpoint.' },
  { tool: 'retryPipelineRun', purpose: 'Retries a failed pipeline run by creating a new pipeline run instance. This endpoint can only be used for pipeline runs that have failed (execution_status = -1). The retry operation will create a new pipeline run with the same configuration as the original failed run.\n\nUse this endpoint when:\n- A pipeline run has failed and you want to retry it\n- You need to rerun a pipeline with the same configuration\n- Troubleshooting pipeline failures by retrying after fixes\n\nThe response includes the new pipeline run details with updated execution status, timestamps, and run identifiers. The original failed pipeline run remains in the system for audit purposes.\n\nFirst call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'runPipeline', purpose: 'Triggers execution of a specific pipeline. Requires pipeline_id which can be obtained from the /pipelines endpoint. Supports multiple run types: 0=MANUAL (default), 2=RELOAD, 3=BACKFILL, 8=MANUAL_WITH_DATA. Each run type requires specific input_data configuration:\n\n1. MANUAL run (run_type=0): Simplest form, example: {"skip_export_invalid_data":false,"run_type":0}\n\n2. RELOAD run (run_type=2): Requires pipeline_run_config as JSON object with task IDs and fetch types. First call /import_catalog to get pipeline task IDs. Example: {"run_type":2,"pipeline_run_config":{"119050000001390201":{"fetch_type":"IMPORT_SOURCE_FILE","use_existing_data_if_no_new_data":false},"119050000001392155":{"fetch_type":"IMPORT_ALL_DATA","use_existing_data_if_no_new_data":false,"max_file_batch_size":"10"}}}\n- For file datasources (connection.type=1), use fetch_type="NO_DATA" as files don\'t need reload\n- For incremental imports (with fetch_incremented_data=true in import_catalog), use fetch_type="IMPORT_ALL_DATA"\n- For standard database imports, use fetch_type="IMPORT_SOURCE_FILE"\n- Set use_existing_data_if_no_new_data=true to use previously imported data if no new data is found\n- IMPORTANT: pipeline_run_config must be a JSON object, not a string\n\n3. BACKFILL run (run_type=3): Includes time range settings and pipeline_run_config. Example: {"skip_export_invalid_data":false,"run_type":3,"data_intervals":{"rep_info":{"rep_type":"hourly","freq":"1","past":"0"},"timeZone":"GMT +05:30 Asia/Kolkata","start_time":"1756924200000"},"pipeline_run_config":{...}}\n- rep_type: hourly, daily, weekly, monthly - indicates data frequency\n- freq: 1, 2, 3 - how frequent (e.g., every 1 hour)\n- past: offset (e.g., 0 means current hour)\n- timeZone: timezone in "GMT +/-HH:MM Region/City" format\n- start_time/end_time: epoch milliseconds for date range\n\n4. MANUAL_WITH_DATA run (run_type=8): Includes pipeline_run_config. Example: {"skip_export_invalid_data":false,"run_type":8,"pipeline_run_config":{...}}\n\nAll pipeline tasks from import_catalog should be included in pipeline_run_config.' },
  { tool: 'schedulePipeline', purpose: 'Creates a schedule for automated pipeline execution. Requires pipeline_id from the /pipelines endpoint. Before scheduling complex pipelines with data sources, first call /import_catalog to get task IDs and configuration details.\n\nSchedule configuration includes:\n1. rep_info: Controls schedule frequency\n   - rep_type: "hourly", "daily", "weekly", "monthly" - indicates run frequency\n   - freq: "1", "2", "3" - how frequent (e.g., every 1 hour)\n   - past: "0" - offset (e.g., 0 means current hour)\n\n2. timeZone: Timezone in "GMT +/-HH:MM Region/City" format\n\n3. schpipelineconfig: Pipeline-level settings like skip_export_invalid_data\n\n4. pipeline_run_config: Task-specific configurations, same format as in the /run API\n   - Keys are task IDs from import_catalog\n   - Values specify fetch types based on task nature:\n     - For standard imports: {"fetch_type":"IMPORT_SOURCE_FILE","use_existing_data_if_no_new_data":false}\n     - For incremental imports: {"fetch_type":"IMPORT_ALL_DATA","use_existing_data_if_no_new_data":false,"max_file_batch_size":"10"}\n\nAll pipeline tasks from import_catalog should be included in pipeline_run_config. The schedule will automatically execute the pipeline based on the specified frequency and configuration.' },
  { tool: 'See_Pipeline_Jobs_for_this_Portal', purpose: 'Returns a paginated list of all pipeline job runs for the specified portal. Supports pagination via list_info.start_index and list_info.row_count parameters. Filtering is available using list_info.search_criteria array to narrow results by execution_status (1=success, -1=failure, 0=in progress, -3=cancelled), type (0=MANUAL, 1=SCHEDULE, 2=RELOAD, 3=BACKFILL, 4=SAMPLE_REFRESH, 5=WEBHOOK, 6=FLOW, 7=ANALYTICS_SCHEDULE, 8=MANUAL_WITH_DATA), created_time (using epoch milliseconds with \'between\' condition for date ranges), pipeline name (using \'contains\' condition), or other fields. Supports sorting via list_info.sort_field and list_info.sort_order. For troubleshooting failed jobs (execution_status=-1), use the pipeline run id from pipelineruns array with /pipelineruns/{pipeline_run_id}/info endpoint to get detailed task-level error information and failure reasons. Useful for monitoring pipeline executions, auditing job outcomes, and analyzing resource consumption.' },
  { tool: 'updateConnection', purpose: 'To update the existing connection. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'updateDatasetsBulk', purpose: 'To update datasets' },
  { tool: 'updateDatasetsForProjectId', purpose: 'To update datasets under specific projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'updatePipeline', purpose: 'To update pipelines' },
  { tool: 'updatePipelineForProjectId', purpose: 'To update pipelines under specific projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'updatePipelineSchedule', purpose: 'Updates an existing schedule for automated pipeline execution. Uses the same parameters and configuration format as creating a schedule. Requires pipeline_id from the /pipelines endpoint. Before updating complex pipelines with data sources, first call /import_catalog to get task IDs and configuration details.\n\nSchedule configuration includes:\n1. rep_info: Controls schedule frequency\n   - rep_type: "hourly", "daily", "weekly", "monthly" - indicates run frequency\n   - freq: "1", "2", "3" - how frequent (e.g., every 1 hour)\n   - past: "0" - offset (e.g., 0 means current hour)\n\n2. timeZone: Timezone in "GMT +/-HH:MM Region/City" format\n\n3. schpipelineconfig: Pipeline-level settings like skip_export_invalid_data\n\n4. pipeline_run_config: Task-specific configurations, same format as in the /run API\n   - Keys are task IDs from import_catalog\n   - Values specify fetch types based on task nature:\n     - For file datasources (connection.type=1): {"fetch_type":"NO_DATA"}\n     - For incremental imports: {"fetch_type":"IMPORT_ALL_DATA","use_existing_data_if_no_new_data":false,"max_file_batch_size":"10"}\n     - For standard database imports: {"fetch_type":"IMPORT_SOURCE_FILE","use_existing_data_if_no_new_data":false}\n\nAll pipeline tasks from import_catalog should be included in pipeline_run_config. The updated schedule will automatically execute the pipeline based on the new specified frequency and configuration.' },
  { tool: 'updateProject', purpose: 'To update projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_All_Pipelines', purpose: 'To get pipelines. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_All_Pipelines_in_a_Workspace', purpose: 'To get pipelines under specific projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_All_Stages', purpose: 'To get datasets. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_All_Stages_in_a_Workspace', purpose: 'To get datasets under specific projects. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_Connection_Details', purpose: 'To get connection details. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_Default_Portal_Details', purpose: 'To Get default dataprep Portal Details. This endpoint provides the portal_name required for most other API endpoints. Call this endpoint at the beginning of your integration workflow and use the returned portal_name value in the path of other endpoints.' },
  { tool: 'View_Pipeline_Details', purpose: 'Returns detailed information about a specific pipeline run, including task-level execution details for troubleshooting failed jobs. Use the pipeline run ID from get_pipeline_jobs response (pipelineruns array -> id field). In response.pipelinerun.pipelinetaskinstances array, each pipelinetask\'s type indicates: 5=extract task, 7=raw parse, 10=transform task, 15=staged extract task, 20=load/export, 25=code studio. The response.pipelinerun also includes row_count and storage_used metrics. Essential for debugging failed pipeline executions by examining individual task failures and error messages.' },
  { tool: 'View_Pipeline_Run_Details', purpose: 'Returns detailed information about a specific pipeline run, including task-level execution details for troubleshooting failed jobs. Use the pipeline run ID from get_pipeline_jobs response (pipelineruns array -> id field). In response.pipelinerun.pipelinetaskinstances array, each pipelinetask\'s type indicates: 5=extract task, 7=raw parse, 10=transform task, 15=staged extract task, 20=load/export, 25=code studio. The response.pipelinerun also includes row_count and storage_used metrics. Essential for debugging failed pipeline executions by examining individual task failures and error messages.\n\nUse this endpoint when:\n- Pipeline execution_status = -1 (failed) in get_pipeline_jobs response\n- Need detailed task-level error information\n- Troubleshooting specific pipeline run failures\n- Analyzing task execution order and dependencies\n\nFirst call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_Pipeline_Runs', purpose: 'To get pipelineruns. First call /dataprepapi/portalsetups/get_default_portal to get portal_name, then use that value in this endpoint\'s path.' },
  { tool: 'View_Pipeline_Schedule', purpose: 'Retrieves the current schedule configuration for a pipeline. Returns all schedule details including repetition settings, timezone, pipeline configuration, and task-specific settings. Also provides information about the next scheduled run time and the status of the most recent execution.' },
];

