const SOCIAL_TOOLS = [
  { tool: 'createSocialDraft', purpose: 'Creates a new draft post with content targeting one or more social networks. The request body supports multi-channel customization including per-network mentions, geolocations, media attachments, link previews, first comments, polls, and scheduling configuration. Set type=6 for drafts. IMPORTANT: Before calling this endpoint, you MUST first call validateSocialPost with the same post body. Only proceed with draft creation if validation returns no errors. This prevents saving drafts with invalid content that will fail when later scheduled or published.' },
  { tool: 'createSocialPinterestBoard', purpose: 'Creates a new Pinterest board for the brand\'s connected Pinterest channel. The board can be created as public or secret. Returns the newly created board object with its id, name, and privacy setting.' },
  { tool: 'createSocialSchedule', purpose: 'Creates a new scheduled post with content targeting one or more social networks. The request body supports multi-channel customization including per-network mentions, geolocations, media attachments, link previews, first comments, polls, and scheduling configuration. Set type=1 for normal schedule, type=2 for SmartQ, type=3 for repeat schedule. The schedule_time field is required for scheduled posts. Do not use this endpoint for direct/immediate publishing; use /social/v2/post/publish instead. IMPORTANT: Before calling this endpoint, you MUST first call validateSocialPost with the same post body. Only proceed with scheduling if validation returns no errors. This prevents publish failures due to character limits, missing media, invalid board_id, or network-specific constraint violations.' },
  { tool: 'deleteSocialDraft', purpose: 'Deletes a draft post by post_id. The draft and all its channel-level content are permanently removed.' },
  { tool: 'deleteSocialSchedule', purpose: 'Deletes a scheduled post by post_id. The scheduled post and all its channel-level content are permanently removed.' },
  { tool: 'getSocialBrands', purpose: 'Fetches social brands accessible to the authenticated user under a given portal. Without brand_id, returns all brands in the portal. With brand_id, returns information about that specific brand as a list. Each brand includes connected channels, service associations, timezone, and location details. Requires the portal header to identify the target portal.' },
  { tool: 'getSocialChannels', purpose: 'Fetches the channels connected (either in active or reconnect state) in the given brand. User must have access (either all or limited channels) to the brand. All validations (space, user, brand) will be carried out. Returns channels with their connection status, publishing capability, and network details.' },
  { tool: 'getSocialDraft', purpose: 'Returns the full details of a single draft post by post_id, including channel-level customizations such as mentions, geolocations, media attachments, link previews, and repetition schedule configuration.' },
  { tool: 'getSocialMediaLibrary', purpose: 'Returns paginated media assets from the brand\'s media library. Supports filtering by library type (sociallibrary, pixabay, pexels, giphy) and pagination via offset/limit or page/per_page parameters. Each media asset includes file metadata such as format, dimensions, size, and upload time.' },
  { tool: 'getSocialNetworkProperties', purpose: 'Returns the basic configurations and functionalities allowed for the given user and brand based on the license and various settings. Provides compose window configurations such as character limits, media constraints, supported features, and validation rules per social network.' },
  { tool: 'getSocialPinterestBoards', purpose: 'Returns the Pinterest boards available for a brand\'s connected Pinterest channel. Boards are paginated and can be filtered by limit. Use the cursor from the response to fetch the next page of results.' },
  { tool: 'getSocialPortals', purpose: 'Fetches social portals accessible to the authenticated user. Without portal_id, returns all portals. With portal_id, returns information about that specific portal as a list. Each portal includes brand counts, plan details, user roles, and connected services.' },
  { tool: 'getSocialPostCount', purpose: 'Returns aggregate counts of posts for a brand grouped by status. Provides the total number of draft posts, posts pending approval, scheduled posts, and failed (unpublished) posts. Useful for dashboards, badges, and quick-glance summaries of the publishing pipeline.' },
  { tool: 'getSocialSchedule', purpose: 'Returns the full details of a single scheduled post by post_id, including channel-level customizations such as mentions, geolocations, media attachments, link previews, and repetition schedule configuration.' },
  { tool: 'getSocialUsers', purpose: 'Fetches the list of users available in a brand. Supports filtering by permission type (e.g., REACH_NEW_POST), network names, and user status. Returns user details including role, approval permissions, admin status, and profile image.' },
  { tool: 'listSocialDrafts', purpose: 'Returns a paginated list of draft posts for a brand. Supports filtering by social network and user. Results include basic draft metadata such as post ID, message preview, creation time, schedule time, and targeted networks.' },
  { tool: 'listSocialSchedules', purpose: 'Returns a paginated list of scheduled posts for a brand. Supports filtering by social network and post type. Results include basic post metadata such as post ID, message preview, creation time, schedule time, and targeted networks.' },
  { tool: 'publishSocialPost', purpose: 'Publishes a post immediately to one or more social networks. This is equivalent to creating a scheduled post with `is_publish_now` set to true. The request body uses the same messages structure as create schedule, supporting channel-level customizations such as mentions, geolocations, media attachments, link previews, first comments, and polls. IMPORTANT: Before calling this endpoint, you MUST first call validateSocialPost with the same post body. Only proceed with publishing if validation returns no errors. This prevents publish failures due to character limits, missing media, invalid board_id, or network-specific constraint violations.' },
  { tool: 'updateSocialDraft', purpose: 'Updates an existing draft post. Can change content, schedule, channels, or convert a draft (type=6) to a scheduled post (type=1). The post_id must be included in the request body under post.post_id. Set oldposttype to the original type when converting. IMPORTANT: Before calling this endpoint, you MUST first call validateSocialPost with the same post body. Only proceed with updating the draft if validation returns no errors. This prevents update failures due to character limits, missing media, invalid board_id, or network-specific constraint violations.' },
  { tool: 'updateSocialSchedule', purpose: 'Updates an existing scheduled post. Can change content, schedule time, channels, or post type. The post_id must be included in the request body under post.post_id. Set oldposttype to the original type when changing the post type. IMPORTANT: Before calling this endpoint, you MUST first call validateSocialPost with the same post body. Only proceed with updating the schedule if validation returns no errors. This prevents update failures due to character limits, missing media, invalid board_id, or network-specific constraint violations.' },
  { tool: 'uploadSocialMedia', purpose: 'Uploads an image file to the brand\'s media library using multipart/form-data. The response contains the file ID and image path which should be used when attaching media to post schedules or drafts.' },
  { tool: 'uploadSocialMediaFromUrl', purpose: 'Uploads an image to the brand\'s media library from a remote URL. The response contains the file ID and image path which should be used when attaching media to post schedules or drafts.' },
  { tool: 'validateSocialPost', purpose: 'Validates a post object before scheduling or publishing. Accepts the same request body structure as create schedule or create draft. Returns validation results indicating whether the post content meets all network-specific requirements such as character limits, media constraints, and channel configurations. This endpoint MUST be called before createSocialSchedule, publishSocialPost, createSocialDraft, updateSocialDraft, or updateSocialSchedule. Pass the exact same post body you intend to schedule, publish, or update. Only proceed if validation returns no errors.' },
];

