type ServiceId = (typeof SERVICES)[number]['id'];
type TabId = 'about' | 'tool-list' | 'common-usecases';

const TABS: { id: TabId; label: string }[] = [
  { id: 'about', label: 'About' },
  { id: 'tool-list', label: 'Tool List' },
  { id: 'common-usecases', label: 'Common Usecases' },
];

/* ─────────────────────────────────────────────
   Search index — maps every serviceId to its tool list
   (inline arrays are duplicated here so search works without touching JSX)
───────────────────────────────────────────── */

const ANALYTICS_TOOLS_INLINE = [
  { tool: 'addAggregateFormula', purpose: 'Add an aggregate formula column to a target view in a workspace. Requires: - org-id - workspace-id - view-id Use getViewDetails to validate the target view metadata before adding formulas. Required Parameters: JSON formula definition (name and expression). Typical workflow: 1) Inspect target view metadata 2) addAggregateFormula. The formula must be a valid aggregation (e.g. SUM(), AVG(), COUNT(), MAX(), MIN(), or other aggregate functions) and cannot be a simple non-aggregated expression.' },
  { tool: 'addRow', purpose: 'Adds a single row to the specified table. Use this when inserting one new record at a time. For bulk inserts (multiple rows or large datasets), use the Bulk Import API instead.' },
  { tool: 'createExportJobSQLQuery', purpose: 'Create an export job using a MySQL-compatible SQL SELECT to export data asynchronously. Important: use Metadata APIs first to avoid wrong identifiers: 1) Get Views (workspace) to list available views. 2) Get View Details (view-id) to get exact table/column names. Then build the SQL using those exact names. Workflow: 1) Create Export Job: call API with valid SQL SELECT; receive JOBID. 2) Check Status: poll Get Export Job Details with JOBID every few seconds; read JOBCODE: - 1001 Not initiated (wait/retry) - 1002 In progress (keep polling) - 1003 Error (stop, investigate) - 1004 Completed (download) - 1005 Not found (stop, verify JOBID) 3) Download: when 1004, call Download Exported Data. Notes: file available 1 hour after completion; max 5 concurrent export jobs/org.' },
  { tool: 'createFolder', purpose: 'Creates a folder under a specified workspace to organize views (tables, reports, dashboards). Folders support exactly 2 levels of nesting: a workspace can contain any number of root-level folders (level 1), and each root-level folder can contain any number of sub-folders (level 2). Sub-folders cannot contain further nested folders - only 1 level of sub-folders is supported. Requires org-id and workspace-id. To create a sub-folder, provide `parentFolderId` in the CONFIG (use getFolders to obtain the parent folder ID). Omit `parentFolderId` to create a root-level folder. After creating a folder, use moveViewsToFolder to organize existing views into it.' },
  { tool: 'createQueryTable', purpose: 'Create a query table using a SQL SELECT statement in a workspace. Query tables are (materialized) views derived from source tables/query tables. Requires: - org-id - workspace-id Before composing SQL, use getViews and getViewDetails to confirm exact table and column names. Request body: CONFIG: JSON query table definition. Typical workflow: 1) Discover source metadata 2) createQueryTable 3) getViews to verify the new query table.' },
  { tool: 'createReport', purpose: 'Create a report in a workspace (chart, pivot, or summary) using an existing base table/query table. Requires: - org-id - workspace-id - Use getViews to confirm the base table/view exists before creating the report. Request body: CONFIG: JSON report definition (report type, axes, filters). Typical workflow: 1) getViews to identify base view 2) createReport 3) getViews to verify the new report.' },
  { tool: 'createTable', purpose: 'Create a table inside a workspace. In Zoho Analytics, tables are views under a workspace. Requires: - org-id - workspace-id Request body: CONFIG: JSON table definition (columns and table metadata). Typical workflow: 1) createTable 2) getViews to confirm the created table view.' },
  { tool: 'createWorkspace', purpose: 'Create a new blank workspace inside a Zoho Analytics organization. Requires: -org-id Request body: CONFIG: JSON configuration for the workspace.' },
  { tool: 'deleteFolder', purpose: 'Permanently delete a folder from a workspace. Optionally delete all views contained within the folder and their dependents. Requires org-id, workspace-id, and folder-id. Use getFolders to look up the folder ID. If the folder contains views you want to preserve, move them first using moveViewsToFolder before deleting the folder. Typical workflow: 1) getFolders to get the folder ID 2) (optional) moveViewsToFolder to relocate views you want to keep 3) deleteFolder' },
  { tool: 'deleteRows', purpose: 'Deletes rows from the specified table. Use this to remove specific records matching a filter criteria, or to clear all rows from the table at once.' },
  { tool: 'deleteView', purpose: 'Move a workspace view to trash. This can delete tables, query tables, reports, charts, or dashboards by view-id. Requires: org-id workspace-id view-id Request body (optional): CONFIG: JSON options for delete behavior, such as deleting dependent views. Typical workflow: 1) Validate target with getViews/getViewDetails 2) deleteView.' },
  { tool: 'downloadExportedData', purpose: 'Download the exported output for a completed asynchronous bulk export job. Requires: - org-id - workspace-id - job-id Only call this after getExportJobDetails reports the job is completed (e.g., jobCode for completion). The response body is the exported file content; the returned Content-Type depends on the export format configured during job creation (e.g., CSV/JSON/XML/XLS/PDF/images, etc.). Note: the exported file is available only for a limited time (expiry returned by job details).' },
  { tool: 'editQueryTable', purpose: 'Update the SQL definition of an existing query table in a workspace. Use this when you need to modify the underlying SELECT query of a query table - for example, to add/remove columns, change joins, or update filters. Requires org-id, workspace-id, and the table-id of the query table to update. Before editing, use getQueryTableDetails to inspect the current SQL query and column structure. Use getViews to confirm exact table and column names referenced in the new SQL query. Typical workflow: 1) getQueryTableDetails to review current definition 2) editQueryTable with the updated SQL 3) getQueryTableDetails to verify changes.' },
  { tool: 'exportDataView', purpose: 'Synchronously export data from a specific view in a Zoho Analytics workspace and receive the content directly in the response. Requires: - org-id - workspace-id - view-id (the target view to export from; obtain from getViews) - CONFIG: stringified JSON specifying the responseFormat ("csv", "json", or "xml"). Always default to "csv" unless the user explicitly requests a different format. Restrictions - this endpoint cannot be used for: - Tables with more than one million rows - Tables and Views from live connect workspaces - Dashboard and QueryTable view types For those cases, use the Asynchronous Export tool (createExportJobSQLQuery) instead. The response body is the exported content. The Content-Type depends on the responseFormat (text/csv, application/json, or application/xml).' },
  { tool: 'getAllWorkspaces', purpose: 'List all workspaces available to the authenticated user within a specific organization. Requires org-id (passed as the org-id parameter). Use this when you want the complete set of accessible workspaces (owned + shared) in the org, before filtering further.' },
  { tool: 'getExportJobDetails', purpose: 'Retrieve the current status and details of an asynchronous bulk export job. Requires: -org-id -workspace-id -job-id (returned from createExportJobSQLQuery) The response includes: - jobCode and jobStatus describing the job state - downloadUrl when the job is completed - expiryTime indicating when the download link expires Poll this endpoint periodically after creating an export job. Stop polling when: jobCode indicates completion (then download), or jobCode indicates error/not found (then handle failure).' },
  { tool: 'getFolders', purpose: 'List all folders in a specified workspace. In Zoho Analytics, folders are used to organize views (tables, reports, dashboards) within a workspace. Returns folder metadata such as folder IDs, names, and descriptions. Requires org-id and workspace-id. Use this to discover the folder structure of a workspace before creating new views, moving views to folders, or when you need folder IDs for createFolder, moveViewsToFolder, or renameFolder operations.' },
  { tool: 'getOrganizations', purpose: 'List the organizations (orgs) that the current authenticated user can access in Zoho Analytics. Use this as the first step to obtain a valid org-id for subsequent calls (workspaces, views, bulk export). Returns basic org metadata (e.g., org identifiers and names) for all orgs accessible to the user.' },
  { tool: 'getOwnedWorkspaces', purpose: 'List only the workspaces that are owned by the authenticated user, within a given organization. Requires org-id. Use this when the workflow specifically needs workspaces where the user is the owner (e.g., for admin-like operations or ownership-based filtering).' },
  { tool: 'getQueryTableDetails', purpose: 'Returns details of the specified query table. Returns the complete SQL query definition, column metadata (name, data type, etc.), and other relevant information about the query table. Requires org-id, workspace-id, and query-table-id. Use this tool to retrieve the SQL query and column details for a query table when you have its ID (e.g., from getViews) and need to understand its structure or definition, before making updates or using it in other operations' },
  { tool: 'getViewDetails', purpose: 'Fetch detailed metadata for a single Zoho Analytics view identified by view-id. A view can represent items such as: - Table - Query Table - Report - Pivot View - Chart - Dashboard Requires: - org-id (organization context) - view-id (the target view) Optional query parameter: - CONFIG: stringified and URL-encoded JSON controlling additional metadata to include. Example (before URL-encoding): {"withInvolvedMetaInfo": true} Use this endpoint when you already have the view-id (typically from getViews) and need full view metadata and optional dependency/involved-meta information.' },
  { tool: 'getViews', purpose: 'List the views available inside a specific workspace. In Zoho Analytics, a view is any workspace asset that can be referenced by a view-id, including: - Tables (data tables) - Query Tables (tables created from SQL queries) - Reports (tabular reports) - Pivot Views (pivot tables) - Charts (graphical reports) - Dashboards (collections of reports/charts) Requires org-id and workspace-id. Optionally pass CONFIG to filter by view type, search by keyword, sort, and paginate results. Use this endpoint to discover view-ids before calling getViewDetails.' },
  { tool: 'moveViewsToFolder', purpose: 'Move one or more views (tables, query tables, reports, charts, or dashboards) into a specified folder within a workspace. Use this to organize workspace assets into folders after creation, or to reorganize existing views. Requires org-id and workspace-id. Use getFolders to look up the target folder ID, and getViews to look up the view IDs to move. Typical workflow: 1) getFolders to get the target folder ID 2) getViews to get the view IDs to move 3) moveViewsToFolder' },
  { tool: 'renameFolder', purpose: 'Rename an existing folder in a workspace, and optionally update its description. Use this when you need to change a folder\'s display name or update its description. Requires org-id, workspace-id, and folder-id. Use getFolders to look up the folder ID before calling this endpoint.' },
  { tool: 'updateRows', purpose: 'Updates one or more rows in the specified table. Use this to modify existing records - either rows matching a filter criteria or all rows at once. Supports upsert behavior via the addIfNotExist flag.' },
];

const APPTICS_TOOLS_INLINE = [
  { tool: 'getActivedeviceCountByDate', purpose: 'Retrieves the daily count of unique active devices for each platform over the specified date range. The response groups data by platform (e.g., iOS, Android, macOS, tvOS), and within each platform, provides a list of dates and their corresponding active device counts. Each date is returned as a UNIX epoch timestamp in milliseconds. Use this endpoint to: - Visualize active user trends across platforms - Monitor device engagement over time - Compare usage across different environments and date ranges This API is especially useful for generating platform-wise activity charts, daily active device reports, and monitoring rollout or adoption impact over time.' },
  { tool: 'getAllActivedeviceStats', purpose: 'Retrieves the number of unique active devices for the given date range, grouped by one or two dimensions such as date, platform, app version, country, bundle, or device type. The \'group\' parameter defines the grouping logic: - Single group (e.g., \'appversion\'): Returns a flat mapping of app versions to active device counts. - Multi-group (e.g., \'date,platform\'): Returns a nested structure where the outer group (e.g., platform) maps to inner group values (e.g., date) and their corresponding counts. Example use cases: - \'group=date,platform\' - Track daily active devices by platform - \'group=appversion\' - See how many devices were active for each app version Dates in the response follow the \'dd-MM-yyyy\' format. This API is helpful for measuring reach, engagement trends, or validating growth across platforms or versions over time.' },
  { tool: 'getAllApiStats', purpose: 'Retrieves usage statistics for configured APIs such as platform, date, app version, country, or device type for the specified date range. The response structure adapts based on the \'group\' parameter: - Single group (e.g., \'appversion\'): Returns a flat mapping of group values to API call counts. - Multi-group (e.g., \'date,platform\'): Returns a nested mapping with the outer group (e.g., platform) containing inner group values (e.g., date) and their corresponding counts. Sample use cases: - \'group=date,platform\' - Track daily API calls per platform - \'group=appversion\' - Aggregate API usage across different app versions Dates in the response are formatted as \'dd-MM-yyyy\'. This API is ideal for analyzing backend service usage patterns, identifying version/platform-level trends, and exporting usage metrics for reporting.' },
  { tool: 'getAllEventStats', purpose: 'Retrieves event count summaries aggregated across one or two grouping dimensions, such as date, platform, country, app version, device type, or event for the specified date range. The response format adapts based on the specified \'group\' parameter: - Single group (e.g., \'appversion\'): Returns a flat mapping of group values to event counts. - Multi-group (e.g., \'date,platform\'): Returns a nested mapping of the primary group (e.g., platform) to the secondary group (e.g., date) and their corresponding counts. - \'event\' as a group key returns counts keyed by event name. Sample scenarios: - \'group=appversion\' - Count of events grouped by app version - \'group=country,date\' - Count of events by country and date - \'platform\': Maximum one platform (e.g., "iOS") - \'groupname\': Event group name (e.g., "user_auth") - \'eventname\': Specific event name (e.g., "login_success") Useful for cohort analysis, feature adoption tracking.' },
  { tool: 'getAllScreenStats', purpose: 'Retrieves the count of screen views aggregated by one or two grouping dimensions such as platform, date, app version, country, or device type for the specified date range. The response structure adapts based on the \'group\' parameter: - Single group (e.g., \'appversion\'): Returns a flat key-value map where keys are group values and values are screen counts. - Multi-group (e.g., \'platform,date\'): Returns a nested object with outer keys as the first group (e.g., platform), and inner keys as the second group (e.g., date). - \'group=platform,date\' - Screen counts by day for each platform - \'group=appversion\' - Total screen views grouped by app version Parameters such as \'screenname\' (specific screen identifier), \'platform\', and pagination (\'limit\' and \'offset\') help refine the result set. Useful for analyzing UI engagement trends, navigation behavior, and platform-specific screen activity over time.' },
  { tool: 'getAllSessionStats', purpose: 'Retrieves session count statistics aggregated by one or two grouping dimensions such as date, platform, app version, country, or device type for the specified date range. The response structure adapts based on the \'group\' parameter: - Single group (e.g., \'appversion\'): Returns a flat key-value map of group values to session counts. - Multi-group (e.g., \'date,platform\'): Returns a nested mapping with outer keys as the first group and inner keys as the second group. Useful for understanding user session patterns, session duration trends, and platform-specific engagement analysis.' },
  { tool: 'getAllStoreReviewAppConfigurations', purpose: 'Returns the store app configuration metadata (configured Play Store and App Store apps, their AAIDs, package names, etc.) for the current project. Use this as the **first call** to discover which `googleAaid` / `appleAaid` values are available for filtering on other AllStore endpoints. The response contains `playstoreintegrations` and/or `appstoreintegrations` arrays. Each entry includes an `AAID` field - pass these as `googleAaid` (for Play Store) or `appleAaid` (for App Store) on list/trend/group/getAppVersions calls. Example response: ```json { "result": "success", "data": { "appstoreintegrations": [ { "AuthID": 51000286562011, "IsReviewEnabled": true, "BundleID": "com.zoho.apptics", "AAID": 51000292746011, "IsAvailableInStore": true, "ProjectID": 51000290959185, "pids": [54000000018013], "AppleAppID": 6448983128 } ] } } ```' },
  { tool: 'getAllStoreReviewAppVersions', purpose: 'Returns the available app versions for the specified Play Store and/or App Store app IDs. Use the returned versions to populate the appVersions filter on other AllStore endpoints.' },
  { tool: 'getAllStoreReviewsGroupStats', purpose: 'Retrieves grouped statistics for combined Play Store and App Store reviews. The required \'groupby\' parameter determines the aggregation dimension. Supports all review filters plus a mode parameter.' },
  { tool: 'getAllStoreReviewsList', purpose: 'Retrieves a paginated list of reviews from both Play Store and App Store. Supports filtering by date range, star rating, sentiment, country, language, reply status, spam classification, device info, app versions, and custom tags. Returns reviewer name, review text, rating, date, device info, and developer response if any.' },
  { tool: 'getAllStoreReviewsTrend', purpose: 'Retrieves the review trend over time for combined Play Store and App Store reviews. Returns review count data grouped by date. Supports the same rich filter set as the list endpoint.' },
  { tool: 'getAnrCountByDate', purpose: 'Retrieves Application Not Responding (ANR) statistics grouped by date for the specified date range. ANRs are Android-specific events that occur when the main thread is blocked for too long. The response provides daily ANR counts, useful for tracking ANR trends and correlating with releases.' },
  { tool: 'getAnrSummary', purpose: 'Retrieves a summarized view of Application Not Responding (ANR) statistics for a given date range. Includes total ANR count, affected users, devices, and issue counts. Useful for monitoring overall ANR health and tracking improvements across releases.' },
  { tool: 'getCrashAffectedDevices', purpose: 'Retrieves the list of affected devices for a specific crash issue identified by its unique ID. Shows individual device details that experienced this crash, useful for support and debugging workflows.' },
  { tool: 'getCrashCountByDateForUnique', purpose: 'Retrieves date-wise crash count statistics for a specific crash issue identified by its unique ID. Useful for tracking the frequency trend of a particular crash over time.' },
  { tool: 'getCrashCountByDateWithTimezone', purpose: 'Retrieves crash count statistics grouped by date with timezone support. Similar to crash/countbydate but allows timezone-based time interval grouping. The response provides platform-specific daily crash metrics adjusted to the specified timezone.' },
  { tool: 'getCrashCountByDateWithTimezoneForUnique', purpose: 'Retrieves date-wise crash count statistics with timezone support for a specific crash issue identified by its unique ID. Combines per-issue filtering with timezone-adjusted date grouping.' },
  { tool: 'getCrashDeviceModelData', purpose: 'Retrieves device model distribution data for a specific crash issue identified by its unique ID. Shows which device models are most affected by this crash, useful for identifying hardware-specific issues.' },
  { tool: 'getCrashesByDate', purpose: 'Retrieves crash-related statistics grouped by date and platform for the specified date range. The response contains platform-specific objects (e.g., ios, android), each providing daily metrics for: - crashcount: Number of crashes per day - devicecount / deviceschart: Number of unique devices affected per day - usercount / userschart: Number of unique users affected per day - issuecount / issueschart: Number of unique crash per day Timestamps are returned as UNIX epoch time in milliseconds. Useful for visualizing crash trends over time, platform-wise comparisons, and volume analysis. Supports pagination via limit and offset, and filtering by platform and mode (production or development).' },
  { tool: 'getCrashList', purpose: 'Returns a list of crash summaries for a given date range, optionally filtered by appversion and platform. Each entry includes metadata such as app version, OS type, number of affected users and devices, crash count, and a top-level exception signature. Useful for tracking stability across releases and identifying common failure patterns.' },
  { tool: 'getCrashOsVersionData', purpose: 'Retrieves OS version distribution data for a specific crash issue identified by its unique ID. Shows which OS versions are most affected, useful for identifying OS-specific regressions.' },
  { tool: 'getCrashSummary', purpose: 'Retrieves a summarized view of crash statistics for a given date range, optionally filtered by platform and mode (production or development). The response includes: Total affected users (usercount) Unique crash issues (issuecount) Total crash events (crashecount) Affected devices (devicecount) Additionally, a crashfreeusers percentage is returned to indicate the proportion of users who experienced no crashes during the period. This API is useful for assessing app stability, tracking regressions, and reporting platform-wise crash health over time.' },
  { tool: 'getCrashSummaryWithUniqueMessageId', purpose: 'Retrieves detailed crash metadata and diagnostic trace for a specific crash event identified by \'uniqueMessageID\'. The response includes contextual information such as: - Device Model and OS version details (e.g., \'Model\', \'OS\', \'OSVersion\', \'Edge\', \'BatteryStatus\') - App context (\'AppVersion\', \'AppReleaseVersion\', \'JAnalyticVersion\') - Session metadata (\'SessionStartTime\', \'UserID\', \'DeviceID\', \'NetworkStatus\') - Crash diagnostic info (\'Exception\', \'IssueName\', \'Message\', \'CustomProperties\') The \'HappenedAt\' and \'SessionStartTime\' fields are in epoch milliseconds. Use this endpoint to reproduce, debug, or escalate critical crash events during a specified time range. Supports filtering by \'mode\' (production/development).' },
  { tool: 'getDashboardApplications', purpose: 'Retrieves application details for the dashboard view. Returns a list of applications with their metadata such as app name, bundle ID, platform, and status. Useful for populating application selectors and overview dashboards.' },
  { tool: 'getEventCountByDate', purpose: 'Retrieves event activity grouped by date and platform for the specified date range. The response contains a per-platform array of events. Each event entry includes: - \'EVENT NAME\': The name of the event triggered by the user - \'EVENT COUNT\': Number of times the event occurred - \'DATE\': Epoch timestamp in milliseconds representing the day the event was recorded The endpoint supports filtering by platform, as well as paginating the results using \'limit\' and \'offset\'. Timestamps are returned in UNIX epoch milliseconds and represent the boundary of the date (typically start of day). This API is useful for: - Building date-wise event trend visualizations - Analyzing platform-level feature usage - Debugging spike or drop in event activity over time' },
  { tool: 'getEventCountrywiseSummary', purpose: 'Retrieves a summary of event activity grouped by country for the selected date range. The response includes a flat mapping of country names to their corresponding event counts, aggregated across the specified platforms. Each entry represents the total number of events triggered by users from that country during the selected period. Use this API to analyze geographic distribution of user interactions and identify high- or low-engagement regions across supported platforms (e.g., iOS, Android, macOS, tvOS).' },
  { tool: 'getEventDeviceCount', purpose: 'Retrieves the count of unique active devices that triggered specific custom events within the given date range. The response returns a mapping where each key is an event label (optionally with event group context in parentheses), and the value represents the number of unique devices on which that event was recorded. Useful for measuring event reach, understanding device-level engagement, and evaluating adoption of feature rollouts or UI interactions across production or development environments.' },
  { tool: 'getEventSummary', purpose: 'Returns a platform-wise summary of custom events recorded within a specified date range. The response includes a list of event groups and their corresponding event names, along with the number of times each event was triggered (\'EVENTS COUNT\'). Data is organized by platform (e.g., iOS, Android, macOS, tvOS), with each platform containing multiple grouped event entries. Each event object includes: - EVENT GROUP NAME: Logical category or module the event belongs to - EVENTS NAME: The name of the tracked event - EVENTS COUNT: Number of occurrences for the event The results can be filtered by platform and paginated using \'limit\' and \'offset\'. Useful for behavioral analysis, feature adoption tracking, and validating event instrumentation across platforms.' },
  { tool: 'getExceptionChart', purpose: 'Retrieves time-series chart data for crashes and exceptions within the specified organization and project. Use `group=fatal` to view **crash trends** (daily crash counts over time - equivalent to crash-count-by-date). Use `group=nonfatal` or `group=error` for handled-exception and error trends. Supports filtering by date range and a JSON `filters` object for platform, app version, country, device type, brand, application, OS version, and device model. This is the primary tool for visualizing crash volume over time, spotting crash spikes after releases, and comparing crash rates across filtered dimensions.' },
  { tool: 'getExceptionCountByGroup', purpose: 'Retrieves the total count of crashes or exceptions for a specific group within the given organization and project. The `group` path parameter selects the category: - `fatal` - returns the **total crash count** (app-terminating failures). Use this for crash summary KPIs like total crashes, affected users, and crash-free metrics. - `nonfatal` - returns the count of handled/non-fatal exceptions. - `error` - returns the count of logged errors. Supports advanced filtering via a JSON `filters` object (platform, app version, country, device type, brand, OS version, device model) and pagination via `index` and `limit`. This is the primary tool for answering "how many crashes happened?" or "what is my crash volume?".' },
  { tool: 'getExceptionDevices', purpose: 'Retrieves the list of individual devices affected by a specific crash or exception issue. Returns per-device records including device model, OS version, app version, and crash/exception timestamps. Use this to identify which specific devices experienced a crash, enabling support workflows, user outreach, and on-device reproduction. Identify the issue using `uniqueMessageID`, `exceptionGroup`, `issueName`, or `crashGroup`. Supports additional dimension filtering via the JSON `filters` object and pagination via `index` and `limit`.' },
  { tool: 'getExceptionReportsV2', purpose: 'Retrieves the V2 crash and exception report list for the specified organization and project. When `group=fatal`, this returns the **crash report list** - each row represents a unique crash issue with its issue name, exception signature, affected app versions, total crash count, and affected user/device counts. This is equivalent to the crash list view. When `group=nonfatal` or `group=error`, it returns handled-exception or error reports respectively. Supports filtering by date range and a JSON `filters` object, with pagination via `index` and `limit`. Use this to identify the top crashing issues, track crash distribution across versions, and prioritize fixes.' },
  { tool: 'getProjectDetails', purpose: 'Retrieves detailed information about a specific project. Returns project metadata including project name, creation date, configured platforms, and settings.' },
  { tool: 'getRemoteLoggerStats', purpose: 'Retrieves remote logging statistics for the specified date range. Remote logs are diagnostic logs sent from devices that can be filtered by function name, log message, severity level, device model, device ID, and user. Useful for remote debugging, monitoring log volume, and identifying problematic patterns in production.' },
  { tool: 'getRemoteLoggerSummary', purpose: 'Retrieves a summarized/aggregated view of remote logging statistics for the specified date range. Provides high-level counts and breakdowns of remote log entries by severity level, function, device, and user. Useful for quick at-a-glance monitoring of log volume, severity distribution, and identifying top contributors.' },
  { tool: 'getScreenRetentionStats', purpose: 'Retrieves retention statistics based on screen views for the specified date range. Analyzes how users return to specific screens over time at day, week, or month granularity. Supports include/exclude filters for specific screen names. Useful for measuring feature stickiness, user re-engagement, and navigation pattern analysis.' },
  { tool: 'getUniqueExceptionChart', purpose: 'Retrieves time-series trend data for a specific crash or exception issue within the given organization and project. Shows how the occurrence frequency of a particular crash issue changes over time - is it increasing, decreasing, or stable? Identify the issue using `uniqueMessageID`, `exceptionGroup`, `issueName`, or `crashGroup`. Use this to monitor whether a known crash is regressing after a release, or whether a fix has reduced its occurrence. Equivalent to the per-issue crash trend view in the crash dashboard.' },
  { tool: 'getUniqueExceptionCount', purpose: 'Retrieves the count of unique occurrences for a specific crash or exception issue within the given organization and project. Identifies the issue using any combination of `uniqueMessageID`, `exceptionGroup`, `issueName`, and `crashGroup`. For crash analysis, use `exceptionGroup=fatal` to count how many unique crash occurrences match the identified issue - useful for assessing crash scope and impact. Supports additional dimension filtering via the JSON `filters` object. Use this to answer "how many times did this specific crash happen?".' },
  { tool: 'getUniqueExceptionDeviceDetailsChart', purpose: 'Retrieves device-model and OS-version distribution data for a specific crash or exception issue. Returns breakdowns showing which device models and OS versions are most affected - equivalent to the crash distribution view (device model breakdown + OS version breakdown). Identify the issue using `uniqueMessageID`, `exceptionGroup`, `issueName`, or `crashGroup`. Use this to determine if a crash is hardware-specific (e.g., only on Pixel devices) or OS-specific (e.g., only on Android 14), helping prioritize device-targeted fixes. Supports additional dimension filtering via the JSON `filters` object.' },
  { tool: 'getUniqueExceptionTrace', purpose: 'Retrieves the full stack trace for a specific crash or exception within the given organization and project. Returns the symbolicated trace including method calls, file names, line numbers, and thread information. This is the primary debugging tool - use it to inspect the exact code path that caused a crash (fatal) or exception (nonfatal/error). Identify the issue using `uniqueMessageID`, `exceptionGroup`, `issueName`, or `crashGroup`. Useful for root-cause analysis, reproducing crashes, and filing actionable bug reports with full trace context.' },
  { tool: 'getUserProjects', purpose: 'Retrieves a list of projects associated with the authenticated user' },
  { tool: 'searchEvents', purpose: 'Searches for specific custom events from the BDaaS data store. Allows filtering by event name, group name, platform, and date range. Useful for finding specific event occurrences, debugging event instrumentation, and validating event data pipelines.' },
];

